  async function fetchInternalTrackMetadata(trackId) {
      const maxRetries = 3;
      let attempt = 0;

      while (attempt < maxRetries) {
          try {
              if (internalTokenRefreshPromise) {
                  await internalTokenRefreshPromise;
              }

              const hexId = spotifyHex(trackId);
              
              const currentToken = Spicetify.Platform.Session.accessToken;
              
              const url = `https://spclient.wg.spotify.com/metadata/4/track/${hexId}?market=from_token&alt=json`;
              
              const response = await fetch(url, {
                  headers: {
                      "Authorization": `Bearer ${currentToken}`,
                      "Accept": "application/json"
                  }
              });
              
              if (response.status === 401) {
                  if (!internalTokenRefreshPromise) {
                      console.warn(`[Sort-Play] Token 401. Starting Refresh...`);
                      
                      internalTokenRefreshPromise = (async () => {
                          try {
                              const tokenData = await Spicetify.CosmosAsync.get('sp://auth/v2/token');
                              const newToken = tokenData.accessToken;

                              Spicetify.Platform.Session.accessToken = newToken;
                              
                              await new Promise(r => setTimeout(r, 500));
                              return newToken;
                          } catch (e) {
                              console.error("[Sort-Play] Token refresh failed", e);
                              throw e;
                          } finally {
                              internalTokenRefreshPromise = null;
                          }
                      })();
                  }

                  try {
                      await internalTokenRefreshPromise;
                  } catch (e) {
                      return null;
                  }
                  
                  attempt++;
                  continue; 
              }

              if (!response.ok) return null;
              const body = await response.json();
              if (!body) return null;
              
              return {
                  name: body.name,
                  id: trackId,
                  uri: `spotify:track:${trackId}`,
                  popularity: body.popularity,
                  duration_ms: body.duration,
                  trackNumber: body.number || body.track_number || 0,
                  explicit: body.explicit,
                  album: {
                      name: body.album?.name,
                      id: body.album?.gid ? hexToBase62(body.album.gid) : null,
                      uri: body.album?.gid ? `spotify:album:${hexToBase62(body.album.gid)}` : null,
                      release_date: body.album?.date ? `${body.album.date.year}-${String(body.album.date.month || 1).padStart(2,'0')}-${String(body.album.date.day || 1).padStart(2,'0')}` : null,
                      images: body.album?.cover_group?.image?.map(img => ({ url: `https://i.scdn.co/image/${img.file_id}` })) || []
                  },
                  artists: body.artist?.map(a => {
                      const artistId = a.gid ? hexToBase62(a.gid) : null;
                      return { 
                          name: a.name, 
                          id: artistId,
                          uri: artistId ? `spotify:artist:${artistId}` : null 
                      };
                  }) || [],
                  external_ids: body.external_id ? { isrc: body.external_id.find(i => i.type === 'isrc')?.id } : {}
              };
          } catch (e) {
              console.error("[Sort-Play] Internal Metadata Fetch Error:", e);
              return null;
          }
      }
      return null;
  }

  async function searchTracks(query, limit = 5) {
      const SEARCH_HASH = "131fd38c13431be963a851082dca0108a4200998b886e7e9d20a21fc51a36aaf";

      const res = await Spicetify.GraphQL.Request({
          name: "searchTracks",
          operation: "query",
          sha256Hash: SEARCH_HASH,
          value: null
      }, {
          searchTerm: query,
          offset: 0,
          limit: limit,
          numberOfTopResults: limit,
          includePreReleases: false
      });

      if (res.errors && res.errors.length > 0) {
          throw new Error(res.errors[0].message || "GraphQL search error");
      }

      const rawItems = res.data?.searchV2?.tracksV2?.items || [];
      
      return {
          tracks: {
              items: rawItems.map(i => {
                  const t = i.item.data;
                  return {
                      uri: t.uri,
                      id: t.uri.split(':')[2],
                      name: t.name,
                      artists: t.artists.items.map(a => ({ 
                          name: a.profile.name, 
                          uri: a.uri, 
                          id: a.uri ? a.uri.split(':')[2] : null 
                      })),
                      album: {
                          name: t.albumOfTrack.name,
                          uri: t.albumOfTrack.uri,
                          id: t.albumOfTrack.uri ? t.albumOfTrack.uri.split(':')[2] : null,
                          images: t.albumOfTrack.coverArt?.sources?.map(s => ({ url: s.url })) || []
                      },
                      duration_ms: t.duration.totalMilliseconds,
                      explicit: t.explicit || false,
                      trackNumber: parseInt(t.trackNumber, 10) || 0,
                      is_playable: t.playability?.playable
                  };
              })
          }
      };
  }

  const memorySettings = {};

  const localStorage = {
    getItem(key) {
        if (memorySettings[key] !== undefined) return memorySettings[key];
        let spVal = null;
        if (Spicetify.LocalStorage) {
            try { spVal = Spicetify.LocalStorage.get(key); } catch(e) {}
        }
        return spVal !== null ? spVal : window.localStorage.getItem(key);
    },
    setItem(key, value) {
        const strVal = String(value);
        memorySettings[key] = strVal;
        idb.set('settings', key, strVal).catch(e => console.error("IDB Save Error:", e));
    },
    removeItem(key) {
        delete memorySettings[key];
        idb.del('settings', key).catch(e => console.error("IDB Delete Error:", e));
    }
  };

  async function hydrateSettings() {
      const storedSettings = await idb.getAll('settings');
      Object.assign(memorySettings, storedSettings);

      const migrationPromises = [];
      let needsMigration = false;
      for (let i = 0; i < window.localStorage.length; i++) {
          const key = window.localStorage.key(i);
          if (key && (key.startsWith('sort-play-') || key.startsWith('sp-'))) {
              if (memorySettings[key] === undefined) {
                  let val = window.localStorage.getItem(key);
                  if (val === null && Spicetify.LocalStorage) {
                      try { val = Spicetify.LocalStorage.get(key); } catch(e) {}
                  }
                  if (val !== null) {
                      memorySettings[key] = val;
                      migrationPromises.push(idb.set('settings', key, val));
                      needsMigration = true;
                  }
              }
          }
      }
      if (needsMigration) {
          await Promise.all(migrationPromises);
          console.log("[Sort-Play] Migrated legacy settings to IndexedDB.");
      }
  }
  
  const idb = {
    db: null,
    mem: {},
    init: () => new Promise((resolve, reject) => {
        const request = indexedDB.open("SortPlayDB", 17);
        request.onupgradeneeded = (e) => {
            const db = e.target.result;
            ['playCounts', 'releaseDates', 'trueReleaseDates', 'scrobbles', 'personalScrobbles', 'lastScrobbledDates', 'palettes', 'aiData', 'trackMetadata', 'generatedCovers', 'jobHistory', 'staticData', 'artistGenres', 'lastfmArtistTags', 'lastfmTrackTags', 'deezerGenres', 'notificationHistory', 'lfmTrends', 'everyNoiseArtistTags', 'settings'].forEach(store => {
                if (!db.objectStoreNames.contains(store)) db.createObjectStore(store);
            });
        };
        request.onsuccess = (e) => {
            idb.db = e.target.result;
            ['playCounts', 'releaseDates', 'trueReleaseDates', 'scrobbles', 'personalScrobbles', 'lastScrobbledDates', 'palettes', 'aiData', 'trackMetadata', 'generatedCovers', 'jobHistory', 'staticData', 'artistGenres', 'lastfmArtistTags', 'lastfmTrackTags', 'deezerGenres', 'notificationHistory', 'lfmTrends', 'everyNoiseArtistTags', 'settings'].forEach(s => idb.mem[s] = new Map());
            resolve();
        };
        request.onerror = (e) => reject(e);
    }),
    isValid: (item, expiryMs) => {
        if (!item || !item.ts) return false;
        if (!expiryMs) return true; 
        return (Date.now() - item.ts) < expiryMs;
    },
    get: (store, key, expiryMs = null) => new Promise(resolve => {
        if (idb.mem[store]?.has(key)) {
            const item = idb.mem[store].get(key);
            if (idb.isValid(item, expiryMs)) return resolve(item.val);
            else idb.mem[store].delete(key);
        }
        if (!idb.db) return resolve(null);
        const tx = idb.db.transaction([store], "readonly");
        const req = tx.objectStore(store).get(key);
        req.onsuccess = () => {
            const result = req.result;
            if (result && idb.isValid(result, expiryMs)) {
                idb.mem[store].set(key, result);
                resolve(result.val);
            } else {
                resolve(null);
            }
        };
        req.onerror = () => resolve(null);
    }),
    getMany: (store, keys, expiryMs = null) => new Promise(resolve => {
        if (!idb.db) return resolve(new Map());
        const results = new Map();
        const missingKeys = [];
        
        keys.forEach(k => {
            if (idb.mem[store]?.has(k)) {
                const item = idb.mem[store].get(k);
                if (idb.isValid(item, expiryMs)) results.set(k, item.val);
                else missingKeys.push(k);
            } else {
                missingKeys.push(k);
            }
        });

        if (missingKeys.length === 0) return resolve(results);

        const tx = idb.db.transaction([store], "readonly");
        const os = tx.objectStore(store);
        
        missingKeys.forEach(key => {
            const r = os.get(key);
            r.onsuccess = () => {
                if (r.result && idb.isValid(r.result, expiryMs)) {
                    results.set(key, r.result.val);
                    idb.mem[store].set(key, r.result);
                }
            };
        });
        tx.oncomplete = () => resolve(results);
        tx.onerror = () => resolve(results);
    }),
    set: (store, key, val) => {
        const item = { val, ts: Date.now() };
        if (idb.mem[store]) idb.mem[store].set(key, item);
        return new Promise(resolve => {
            if (!idb.db) return resolve();
            const tx = idb.db.transaction([store], "readwrite");
            tx.objectStore(store).put(item, key);
            tx.oncomplete = () => resolve();
        });
    },
    setMany: (store, entries) => {
        entries.forEach(e => {
            const item = { val: e.val, ts: Date.now() };
            if (idb.mem[store]) idb.mem[store].set(e.key, item);
        });
        return new Promise(resolve => {
            if (!idb.db || entries.length === 0) return resolve();
            const tx = idb.db.transaction([store], "readwrite");
            const os = tx.objectStore(store);
            entries.forEach(e => {
                os.put({ val: e.val, ts: Date.now() }, e.key);
            });
            tx.oncomplete = () => resolve();
            tx.onerror = () => resolve();
        });
    },
    del: (store, key) => {
        if (idb.mem[store]) idb.mem[store].delete(key);
        return new Promise(resolve => {
            if (!idb.db) return resolve();
            const tx = idb.db.transaction([store], "readwrite");
            tx.objectStore(store).delete(key);
            tx.oncomplete = () => resolve();
        });
    },
    clear: (store) => {
        if (idb.mem[store]) idb.mem[store].clear();
        return new Promise(resolve => {
            if (!idb.db) return resolve();
            const tx = idb.db.transaction([store], "readwrite");
            tx.objectStore(store).clear();
            tx.oncomplete = () => resolve();
        });
    },
    getAll: (store) => new Promise(resolve => {
        if (!idb.db) return resolve({});
        const tx = idb.db.transaction([store], "readonly");
        const req = tx.objectStore(store).getAllKeys();
        const valReq = tx.objectStore(store).getAll();
        tx.oncomplete = () => {
            const result = {};
            if (req.result && valReq.result) {
                req.result.forEach((key, i) => {
                    result[key] = valReq.result[i].val;
                });
            }
            resolve(result);
        };
        tx.onerror = () => resolve({});
    })
  };
  
  async function migrateJobHistoryToIdb() {
    const migrationFlag = "sort-play-history-migrated-v1";
    if (localStorage.getItem(migrationFlag)) return;

    console.log("[Sort-Play] Migrating track history to IDB...");
    const jobsJson = localStorage.getItem("sort-play-dynamic-playlist-jobs");
    if (!jobsJson) {
        localStorage.setItem(migrationFlag, "true");
        return;
    }

    try {
        const jobs = JSON.parse(jobsJson);
        let hasChanges = false;

        for (const job of jobs) {
            if (job.sources) {
                for (const source of job.sources) {
                    if (source.usedTrackURIs && Array.isArray(source.usedTrackURIs) && source.usedTrackURIs.length > 0) {
                        const key = `${job.id}_${source.uri}`;
                        await idb.set('jobHistory', key, source.usedTrackURIs);
                        delete source.usedTrackURIs; 
                        hasChanges = true;
                    }
                }
            }
        }

        if (hasChanges) {
            localStorage.setItem("sort-play-dynamic-playlist-jobs", JSON.stringify(jobs));
            console.log("[Sort-Play] Migration successful. LocalStorage freed.");
        }
        localStorage.setItem(migrationFlag, "true");
    } catch (e) {
        console.error("[Sort-Play] Migration failed:", e);
    }
  }
    
