    const npLastfmToggle = modalContainer.querySelector("#npLastfmToggle");
    const npDeezerToggle = modalContainer.querySelector("#npDeezerToggle");
    const apSpotifyToggle = modalContainer.querySelector("#apSpotifyToggle");
