  document.head.appendChild(styleElement);

  const excludedPlaylistNames = ["New Music Friday", "Discover Weekly", "Release Radar"];

  function getCurrentPlaylistName() {
    const playlistNameElement = document.querySelector(
      ".encore-text.encore-text-headline-large"
    );
    return playlistNameElement ? playlistNameElement.textContent.trim() : null;
  }

  function isLikedSongsPage(uri) {
    if (!uri || typeof uri !== 'string') return false;
    try {
      const uriObj = Spicetify.URI.fromString(uri);
      return uriObj && uriObj.type === Spicetify.URI.Type.COLLECTION && uriObj.category === "tracks";
    } catch (e) {
      return false;
    }
  }

  function isLocalFilesPage(uri) {
    if (!uri || typeof uri !== 'string') return false;
    return uri === "spotify:collection:local-files";
  }

  function getCurrentUri() {
    const path = Spicetify.Platform.History.location?.pathname;
    if (!path) return null;

    const segments = path.split('/').filter(segment => segment.length > 0);
    
    const albumIndex = segments.indexOf('album');
    if (albumIndex > -1 && segments[albumIndex + 1]) {
        return `spotify:album:${segments[albumIndex + 1]}`;
    }
    
    const artistIndex = segments.indexOf('artist');
    if (artistIndex > -1 && segments[artistIndex + 1]) {
        return `spotify:artist:${segments[artistIndex + 1]}`;
    }
    
    const playlistIndex = segments.indexOf('playlist');
    if (playlistIndex > -1 && segments[playlistIndex + 1]) {
        return `spotify:playlist:${segments[playlistIndex + 1]}`;
    }
    
    if (segments.includes('collection') && segments.includes('tracks')) {
        return "spotify:collection:tracks";
    }
    
    if (segments.includes('collection') && segments.includes('local-files')) {
        return "spotify:collection:local-files";
    }
    
    return null;
  }
  
  async function getLikedSongs() {
    try {
      const likedTracksData = await Spicetify.Platform.LibraryAPI.getTracks({
        limit: Number.MAX_SAFE_INTEGER,
      });

      if (!likedTracksData || !likedTracksData.items) {
        throw new Error("Failed to fetch liked songs data.");
      }

      const likedTracks = likedTracksData.items.map((item) => ({
        uri: item.uri,
        uid: item.uid,
        name: item.name,
        albumUri: item.album.uri,
        albumName: item.album.name,
        artistUris: item.artists.map((artist) => artist.uri),
        artistName: item.artists[0]?.name,
        allArtists: normalizeArtistNames(item.artists),
        durationMilis: item.duration.milliseconds,
        durationMs: item.duration.milliseconds,
        playCount: "N/A",
        popularity: null,
        releaseDate: null,
        addedAt: item.addedAt || null,
        explicit: item.isExplicit || item.explicit || false,
        track: {
            album: {
                id: item.album.uri ? item.album.uri.split(":")[2] : null
            },
            name: item.name,
            duration_ms: item.duration.milliseconds,
            id: Spicetify.URI.isLocal(item.uri) ? item.uri : item.uri.split(":")[2],
            explicit: item.isExplicit || item.explicit || false
          }
      }));

      return likedTracks;

    } catch (error)      {
      console.error("Error fetching liked songs:", error);
      showNotification("Failed to fetch liked songs.", true);
      return [];
    }
  }
    
  async function getLocalFilesTracks() {
    try {
        const localTracksData = await Spicetify.Platform.LocalFilesAPI.getTracks();
        if (!localTracksData) {
            throw new Error("Failed to fetch local files data.");
        }

        return localTracksData.map((item) => ({
            uri: item.uri,
            uid: item.uid,
            name: item.name,
            albumUri: item.album.uri,
            albumName: item.album.name,
            artistUris: item.artists.map((artist) => artist.uri),
            artistName: item.artists[0]?.name,
            allArtists: normalizeArtistNames(item.artists),
            durationMilis: item.duration.milliseconds,
            durationMs: item.duration.milliseconds,
            playCount: "N/A",
            popularity: null,
            releaseDate: null,
            addedAt: item.addedAt || null,
            explicit: item.isExplicit || item.explicit || false,
            track: {
                album: {
                    id: item.album.uri ? item.album.uri.split(":")[2] : null,
                    name: item.album.name,
                },
                name: item.name,
                duration_ms: item.duration.milliseconds,
                id: item.uri,
                explicit: item.isExplicit || item.explicit || false
            }
        }));
    } catch (error) {
        console.error("Error fetching local files:", error);
        showNotification("Failed to fetch local files.", true);
        return [];
    }
  }

  const fetchPlaylistContents = async (uri) => (await PlaylistAPI.getContents(uri)).items;

  const parsePlaylistAPITrack = (track) => ({
    uri: track.uri,
    uid: track.uid,
    name: track.name,
    albumUri: track.album.uri,
    albumName: track.album.name,
    artistUris: track.artists.map((artist) => artist.uri),
    allArtists: normalizeArtistNames(track.artists),
    artistName: track.artists[0]?.name,
    durationMilis: track.duration.milliseconds,
    durationMs: track.duration.milliseconds,
    playcount: 0,
    popularity: 0,
    releaseDate: 0,
    addedAt: track.addedAt,
    trackNumber: track.album?.trackNumber || track.trackNumber || 0,
    explicit: track.isExplicit || track.explicit || false,
    track: {
      album: {
        id: track.album.uri ? track.album.uri.split(":")[2] : null
      },
      name: track.name,
      duration_ms: track.duration.milliseconds,
      id: Spicetify.URI.isLocal(track.uri) ? track.uri : track.uri.split(":")[2],
      explicit: track.isExplicit || track.explicit || false
    }
  });

  const getPlaylistTracksSpicetify = async (playlistId) => {
    const playlistUri = `spotify:playlist:${playlistId}`;
    const retries = 5;
    let delay = 1000;

    for (let attempt = 1; attempt <= retries; attempt++) {
        try {
            if (!Spicetify || !URI) {
                throw new Error('Spicetify is not properly initialized');
            }

            if (!playlistId) {
                throw new Error('Invalid playlist ID');
            }

            const playlistContents = await fetchPlaylistContents(playlistUri);
            
            if (!playlistContents || !Array.isArray(playlistContents)) {
                throw new Error('Failed to fetch playlist contents');
            }

            const parsedTracks = playlistContents
                .filter(track => {
                    if (!track || !track.uri) {
                        return false;
                    }
                    return track.uri.startsWith("spotify:track:") || Spicetify.URI.isLocal(track.uri);
                })
                .map(track => {
                    try {
                        return parsePlaylistAPITrack(track);
                    } catch (parseError) {
                        showNotification(
                            'Error processing some tracks. Please try again.',
                            true
                        );
                        return null;
                    }
                })
                .filter(track => track !== null);

            if (parsedTracks.length === 0) {
                throw new Error('No valid tracks found in playlist');
            }

            return parsedTracks;
        } catch (error) {
            console.error(
                `Error fetching playlist tracks (Attempt ${attempt}/${retries}):`,
                error
            );
            
            if (attempt < retries) {
                await new Promise((resolve) => setTimeout(resolve, delay));
                delay *= 2;
            } else {
                console.error(
                    `Failed to fetch playlist tracks after ${retries} attempts.`
                );
                throw error;
            }
        }
    }
  };

  function getArtistDiscographyMap() {
      try { return JSON.parse(localStorage.getItem(STORAGE_KEY_ARTIST_DISCOGRAPHY_MAP) || '{}'); }
      catch(e) { return {}; }
  }

  function addArtistDiscographyMap(artistUri, playlistUri) {
      const map = getArtistDiscographyMap();
      if (!map[artistUri]) map[artistUri] = [];
      map[artistUri] = map[artistUri].filter(uri => uri !== playlistUri);
      map[artistUri].unshift(playlistUri); 
      localStorage.setItem(STORAGE_KEY_ARTIST_DISCOGRAPHY_MAP, JSON.stringify(map));
  }

  async function getUserOwnedPlaylistsInternal() {
      const user = await Spicetify.Platform.UserAPI.getUser();
      const username = user.username;
      const rootlist = await Spicetify.Platform.RootlistAPI.getContents();
      
      const uris = [];
      const traverse = (items) => {
          for (const item of items) {
              if (item.type === 'playlist') {
                  uris.push(item.uri);
              } else if (item.type === 'folder' && item.items) {
                  traverse(item.items);
              }
          }
      };
      traverse(rootlist.items);

      const ownedPlaylists = [];
      const BATCH_SIZE = 100;
      
      for (let i = 0; i < uris.length; i += BATCH_SIZE) {
          const batch = uris.slice(i, i + BATCH_SIZE);
          const promises = batch.map(async (uri) => {
              try {
                  const meta = await Spicetify.Platform.PlaylistAPI.getMetadata(uri);
                  if (meta && meta.owner && (meta.owner.username === username || meta.owner.uri.includes(username))) {
                      return {
                          uri: uri,
                          name: meta.name,
                          images: meta.images,
                          tracks: { total: meta.totalLength }
                      };
                  }
              } catch(e) {}
              return null;
          });
          const results = await Promise.all(promises);
          results.forEach(r => { if(r) ownedPlaylists.push(r); });
      }
      return ownedPlaylists;
  }

  function showArtistDuplicateModal(mappedPlaylists, possiblePlaylists, artistName) {
      return new Promise((resolve) => {
          const overlay = document.createElement("div");
          overlay.className = "sort-play-font-scope";
          overlay.style.cssText = `
              position: fixed; top: 0; left: 0; width: 100%; height: 100%;
              background-color: rgba(0, 0, 0, 0.7); z-index: 3000;
              display: flex; justify-content: center; align-items: center;
              backdrop-filter: blur(8px);
          `;

          const modal = document.createElement("div");
          modal.className = "main-embedWidgetGenerator-container";
          modal.style.cssText = `
              width: 520px !important; background-color: #181818 !important;
              border: 1px solid #282828; border-radius: 20px; display: flex;
              flex-direction: column; max-height: 80vh; overflow: hidden;
          `;

          let selectedUri = mappedPlaylists.length > 0 ? mappedPlaylists[0].uri : (possiblePlaylists.length === 1 ? possiblePlaylists[0].uri : null);

          const renderItem = (p, isMapped) => {
              const cover = p.images?.length ? p.images[p.images.length - 1].url : FALLBACK_COVER_URI;
              const isSelected = p.uri === selectedUri;
              const baseClass = isMapped ? 'playlist-item mapped' : 'playlist-item unmapped';
              const selClass = isSelected ? 'selected' : '';
              return `
                  <div class="${baseClass} ${selClass}" data-uri="${p.uri}">
                      <img src="${cover}" class="playlist-cover">
                      <div class="playlist-info">
                          <div class="playlist-name" title="${escapeHtml(p.name)}">${escapeHtml(p.name)}</div>
                          <div class="playlist-meta">Playlist • ${p.tracks?.total || 0} tracks</div>
                      </div>
                  </div>
              `;
          };

          let listHtml = '';
          if (mappedPlaylists.length > 0) {
              listHtml += mappedPlaylists.map(p => renderItem(p, true)).join('');
          }
          if (possiblePlaylists.length > 0) {
              listHtml += `<div class="unmapped-header">Possible duplicates in your library</div>`;
              listHtml += possiblePlaylists.map(p => renderItem(p, false)).join('');
          }

          modal.innerHTML = `
              <style>
                  .duplicate-modal-body { padding: 16px 24px; flex: 1; overflow-y: auto; scrollbar-width: thin; scrollbar-color: #535353 transparent; }
                  .duplicate-modal-body::-webkit-scrollbar { width: 8px; }
                  .duplicate-modal-body::-webkit-scrollbar-thumb { background-color: #535353; border-radius: 4px; }
                  .playlist-item { display: flex; align-items: center; gap: 12px; padding: 8px; border-radius: 8px; cursor: pointer; border: 1px solid transparent; transition: background-color 0.2s, border-color 0.2s; margin-bottom: 8px; }
                  .playlist-item.mapped { background-color: #282828; border: 1px solid #333; }
                  .playlist-item.unmapped { background-color: #202020; border: 1px solid #2a2a2a; }
                  .playlist-item:hover { background-color: #383838; }
                  .playlist-item.selected { background-color: #3a4f3a; border-color: #1ed760; }
                  .playlist-cover { width: 44px; height: 44px; border-radius: 4px; object-fit: cover; flex-shrink: 0; background-color: #333; }
                  .playlist-info { display: flex; flex-direction: column; overflow: hidden; flex: 1; }
                  .playlist-name { color: white; font-weight: 600; font-size: 14px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; margin-bottom: 2px; }
                  .playlist-meta { color: #b3b3b3; font-size: 12px; }
                  .unmapped-header { font-size: 12px; color: #888; text-transform: uppercase; font-weight: 700; margin: 16px 0 8px 4px; letter-spacing: 0.5px; }
                  
                  .dup-btn { padding: 8px 20px; border-radius: 20px; font-weight: bold; font-size: 13px; cursor: pointer; border: none; transition: background 0.2s, opacity 0.2s; }
                  .dup-btn:disabled { cursor: not-allowed; opacity: 0.5; }
                  .dup-btn.action-btn:hover:not(:disabled) { background: #444 !important; }

                  .duplicate-modal-footer {padding: 16px 24px 24px;border-top: 1px solid #282828;background-color: #181818;display: flex;flex-direction: column; gap: 16px;flex-shrink: 0;
                  }
              </style>
              <div style="padding: 24px 24px 16px; border-bottom: 1px solid #282828; flex-shrink: 0;">
                  <h2 style="margin:0 0 8px 0; color:white; font-size:22px; font-weight:700;">Discography Exists</h2>
                  <p style="margin:0; color:#b3b3b3; font-size:14px; line-height:1.4;">You already have playlists related to <b>${artistName}</b>. Select one to overwrite, or create a brand new playlist.</p>
              </div>
              
              <div class="duplicate-modal-body" id="dup-list-container">
                  ${listHtml}
              </div>

              <div class="duplicate-modal-footer">
                  <label style="color: #b3b3b3; font-size: 13px; display: flex; align-items: center; gap: 10px; cursor: pointer; user-select: none; width: fit-content;">
                      <input type="checkbox" id="dup-dont-show-again" style="accent-color: #1db954; width: 16px; height: 16px; margin: 0;">
                      Don't ask again (Always create new)
                  </label>
                  
                  <div style="display: flex; justify-content: space-between; align-items: center; width: 100%;">
                      <button id="dup-cancel" class="dup-btn" style="background: transparent; border: 1px solid #666; color: white;">Cancel</button>
                      <div style="display: flex; gap: 10px;">
                          <button id="dup-replace" class="dup-btn action-btn" style="background: #333; color: white;" ${!selectedUri ? 'disabled' : ''}>Replace Selected</button>
                          <button id="dup-create" class="dup-btn action-btn" style="background: #333; color: white;">Create New</button>
                      </div>
                  </div>
              </div>
          `;

          document.body.appendChild(overlay);
          overlay.appendChild(modal);

          const listContainer = modal.querySelector("#dup-list-container");
          const replaceBtn = modal.querySelector("#dup-replace");

          listContainer.addEventListener("click", (e) => {
              const item = e.target.closest(".playlist-item");
              if (!item) return;

              listContainer.querySelectorAll(".playlist-item").forEach(el => el.classList.remove("selected"));
              item.classList.add("selected");
              selectedUri = item.dataset.uri;
              
              replaceBtn.disabled = false;
              replaceBtn.style.opacity = "1";
          });

          const close = (actionData) => {
              overlay.remove();
              resolve(actionData);
          };

          modal.querySelector("#dup-cancel").onclick = () => close({ action: 'cancel' });
          modal.querySelector("#dup-create").onclick = () => {
              if (modal.querySelector("#dup-dont-show-again").checked) {
                  showArtistDiscographyDuplicateWarning = false;
                  saveSettings();
              }
              close({ action: 'createNew' });
          };
          replaceBtn.onclick = () => {
              if (selectedUri) {
                  if (modal.querySelector("#dup-dont-show-again").checked) {
                      showArtistDiscographyDuplicateWarning = false;
                      saveSettings();
                  }
                  close({ action: 'replace', uri: selectedUri });
              }
          };

          overlay.onclick = (e) => { if (e.target === overlay) close({ action: 'cancel' }); };
      });
  }
  
  async function getTracksFromFolder(folderUri) {
      try {
          const rootlist = await Spicetify.Platform.RootlistAPI.getContents();
          
          const findFolderItems = (items, targetUri) => {
              for (const item of items) {
                  if (item.uri === targetUri) return item.items || [];
                  if (item.type === 'folder' && item.items) {
                      const found = findFolderItems(item.items, targetUri);
                      if (found) return found;
                  }
              }
              return null;
          };

          const folderItems = findFolderItems(rootlist.items, folderUri);
          if (!folderItems) return [];

          const allTracks = [];
          
          const traverseAndFetch = async (items) => {
              for (const item of items) {
                  if (item.type === 'playlist') {
                      try {
                          const tracks = await getPlaylistTracks(item.uri.split(':')[2]);
                          if (tracks) allTracks.push(...tracks);
                      } catch (e) {
                          console.warn(`Failed to fetch tracks from playlist ${item.name} inside folder`, e);
                      }
                  } else if (item.type === 'folder' && item.items) {
                      await traverseAndFetch(item.items);
                  }
              }
          };

          await traverseAndFetch(folderItems);
          return allTracks;
      } catch (e) {
          console.error("Error getting tracks from folder:", e);
          return [];
      }
  }

  async function getPlaylistTracks(playlistId) {
    try {
        if (!playlistId || typeof playlistId !== 'string') {
            throw new Error('Invalid playlist format');
        }

        const tracks = await getPlaylistTracksSpicetify(playlistId);
        
        if (!Array.isArray(tracks)) {
            throw new Error('Failed to process playlist tracks');
        }

        if (tracks.length > 0) {
            return tracks;
        } else {
            throw new Error('No tracks found in playlist');
        }
    } catch (error) {
        console.error('Error in getPlaylistTracks:', error);
        showNotification(
            `Failed to fetch playlist tracks: ${error.message}. Please try again.`,
            true
        );
    }

    return [];
  }

  async function getAlbumTracks(albumId, knownReleaseDate = null, usePlaylistApi = false) {
    const { CosmosAsync, GraphQL } = Spicetify;
    const albumUri = `spotify:album:${albumId}`;

    const formatImageUrl = (url) => {
        if (!url) return null;
        if (url.startsWith("spotify:image:")) return `https://i.scdn.co/image/${url.split(":")[2]}`;
        return url;
    };

    const fetchAlbumTracksPlaylistAPI = async () => {
        const promise = Spicetify.Platform.PlaylistAPI.getContents(albumUri);
        const contents = await Promise.race([
            promise,
            new Promise((_, reject) => setTimeout(() => reject(new Error("Timeout")), 10000))
        ]);
        if (!contents || !contents.items) throw new Error("PlaylistAPI getContents failed or returned no items");

        const items = contents.items.filter(item => item.type === "track");
        if (items.length === 0) throw new Error("PlaylistAPI returned 0 tracks");

        const releaseDate = knownReleaseDate || null;

        return items.map(item => {
            const artists = item.artists.map(a => ({
                name: a.name,
                uri: a.uri,
                id: a.uri ? a.uri.split(':')[2] : null
            }));
            
            const isExplicit = item.isExplicit || item.explicit || false;
            const durationMs = item.duration?.milliseconds || 0;

            return {
                uri: item.uri,
                uid: item.uid || null,
                name: item.name,
                songTitle: item.name,
                albumUri: albumUri,
                albumName: item.album.name,
                artistUris: artists.map(a => a.uri),
                allArtists: artists.map(a => a.name).join(", "),
                artistName: artists[0]?.name,
                durationMilis: durationMs,
                durationMs: durationMs,
                playcount: 0,
                playCount: "N/A",
                popularity: null,
                releaseDate: releaseDate,
                addedAt: null,
                trackNumber: item.trackNumber || parseInt(item.album?.trackNumber, 10) || 0,
                explicit: isExplicit,
                track: {
                    album: { 
                        id: albumId, 
                        name: item.album.name, 
                        release_date: releaseDate,
                        images: item.album.images ? item.album.images.map(img => ({ url: formatImageUrl(img.url) })) : []
                    },
                    name: item.name,
                    duration_ms: durationMs, 
                    id: Spicetify.URI.isLocal(item.uri) ? item.uri : item.uri.split(':')[2],
                    artists: artists,
                    external_ids: {},
                    trackNumber: item.trackNumber || parseInt(item.album?.trackNumber, 10) || 0,
                    explicit: isExplicit
                }
            };
        });
    };

    const fetchAlbumTracksGQL = async () => {
        const promise = GraphQL.Request(GraphQL.Definitions.queryAlbumTracks, {
            uri: albumUri,
            offset: 0,
            limit: 500,
            locale: "en"
        });
        const res = await Promise.race([
            promise,
            new Promise((_, reject) => setTimeout(() => reject(new Error("Timeout")), 10000))
        ]);

        const album = res.data?.albumUnion;
        const tracks = album?.tracksV2?.items || album?.tracks?.items;
        if (!tracks) throw new Error("GraphQL Album fetch failed");

        const releaseDate = knownReleaseDate || album.date?.isoString || album.date?.year?.toString();

        return tracks.map(item => {
            const t = item.track;
            const artists = t.artists.items.map(a => ({
                name: a.profile.name,
                uri: a.uri,
                id: a.uri ? a.uri.split(':')[2] : null
            }));
            const rawPlaycount = t.playcount ? parseInt(t.playcount, 10) : 0;
            const isExplicit = t.isExplicit || t.explicit || false;

            return {
                uri: t.uri,
                uid: null,
                name: t.name,
                songTitle: t.name,
                albumUri: albumUri,
                albumName: album.name,
                artistUris: artists.map(a => a.uri),
                allArtists: artists.map(a => a.name).join(", "),
                artistName: artists[0]?.name,
                durationMilis: t.duration.totalMilliseconds,
                durationMs: t.duration.totalMilliseconds,
                playcount: rawPlaycount,
                playCount: rawPlaycount > 0 ? rawPlaycount : "N/A",
                popularity: null,
                releaseDate: releaseDate,
                addedAt: null,
                trackNumber: parseInt(t.trackNumber, 10) || 0,
                explicit: isExplicit,
                track: {
                    album: { 
                        id: albumId, 
                        name: album.name, 
                        release_date: releaseDate,
                        images: album.coverArt?.sources?.map(s => ({ url: s.url })) || []
                    },
                    name: t.name,
                    duration_ms: t.duration.totalMilliseconds, 
                    id: Spicetify.URI.isLocal(t.uri) ? t.uri : t.uri.split(':')[2],
                    artists: artists,
                    external_ids: {},
                    trackNumber: parseInt(t.trackNumber, 10) || 0,
                    explicit: isExplicit
                }
            };
        });
    };

    if (usePlaylistApi) {
        try {
            return await fetchAlbumTracksPlaylistAPI();
        } catch (err) {
            console.warn(`[Sort-Play] PlaylistAPI fetch failed for ${albumId}, falling back to GraphQL:`, err);
            try { return await fetchAlbumTracksGQL(); } catch (e) { return []; }
        }
    } else {
        try {
            return await fetchAlbumTracksGQL();
        } catch (err) {
            console.warn(`[Sort-Play] GraphQL fetch failed for ${albumId}, falling back to PlaylistAPI:`, err);
            try { return await fetchAlbumTracksPlaylistAPI(); } catch (e) { return []; }
        }
    }
  }

  async function getArtistTracks(artistUri, isHeadless = false, progressCallback = null) {
    const { Locale, GraphQL, CosmosAsync } = Spicetify;
  
    const queryArtistOverview = Spicetify.GraphQL.Definitions.queryArtistOverview || {
      name: "queryArtistOverview",
      operation: "query",
      sha256Hash: "35648a112beb1794e39ab931365f6ae4a8d45e65396d641eeda94e4003d41497",
    };
  
    if (!isHeadless) {
        mainButton.innerHTML = '<div class="loader"></div>';
        setButtonProcessing(true);
    }
  
    try {
      const artistData = await GraphQL.Request(queryArtistOverview, {
        uri: artistUri,
        locale: Locale.getLocale(),
        includePrerelease: false,
      });
  
      if (artistData.errors) throw new Error(artistData.errors[0].message);
      const artistName = artistData.data.artistUnion.profile.name;

      const allAlbumMetadata = new Map();

      const fetchAlbumIdsGQL = async () => {
          let offset = 0;
          let limit = 100;
          let total = null;
          while (total === null || offset < total) {
              try {
                  const res = await GraphQL.Request(GraphQL.Definitions.queryArtistDiscographyAll, {
                      uri: artistUri,
                      offset: offset,
                      limit: limit
                  });
                  const disc = res?.data?.artistUnion?.discography?.all;
                  if (!disc) break;
                  total = disc.totalCount;
                  
                  disc.items.forEach(group => {
                      if (group.releases && group.releases.items) {
                          group.releases.items.forEach(rel => {
                              const id = rel.uri.split(':')[2];
                              allAlbumMetadata.set(id, { 
                                  type: rel.type || 'album',
                                  date: rel.date?.isoString || rel.date?.year 
                              });
                          });
                      }
                  });
                  offset += limit;
              } catch (e) {
                  console.warn("fetchAlbumIdsGQL failed", e);
                  break;
              }
          }
      };

      const fetchAppearsOnIdsGQL = async () => {
          let offset = 0;
          let limit = 100;
          let total = null;
          while (total === null || offset < total) {
              try {
                  const res = await GraphQL.Request(GraphQL.Definitions.queryArtistAppearsOn, {
                      uri: artistUri,
                      offset: offset,
                      limit: limit
                  });
                  const appearsOn = res?.data?.artistUnion?.relatedContent?.appearsOn;
                  if (!appearsOn) break;
                  
                  total = appearsOn.totalCount;
                  
                  if (appearsOn.items) {
                      appearsOn.items.forEach(item => {
                          const release = item.releases?.items?.[0];
                          if (release) {
                              const id = release.uri.split(':')[2];
                              if (!allAlbumMetadata.has(id)) {
                                  allAlbumMetadata.set(id, { 
                                      type: 'appears_on', 
                                      date: null 
                                  });
                              }
                          }
                      });
                  }
                  offset += limit;
              } catch (e) {
                  break;
              }
          }
      };

      const fetchAppearsOnViaSearch = async () => {
          if (artistName.toLowerCase() === "various artists") return;
          
          const SEARCH_HASH = "131fd38c13431be963a851082dca0108a4200998b886e7e9d20a21fc51a36aaf";
          const currentYear = new Date().getFullYear();
          const timeSlices = ["0-1989", "1990-1999"];
          for (let y = 2000; y <= currentYear + 1; y++) {
              timeSlices.push(y.toString());
          }

          const safeArtistName = artistName.replace(/"/g, '\\"');
          const BATCH_SIZE = 30;
          const targetArtistId = artistUri.split(':')[2];
          
          for (let i = 0; i < timeSlices.length; i += BATCH_SIZE) {
              const batch = timeSlices.slice(i, i + BATCH_SIZE);
              await Promise.all(batch.map(async (slice) => {
                  let offset = 0;
                  let limit = 50;
                  while (offset < 1000) {
                      try {
                          const res = await GraphQL.Request({
                              name: "searchTracks",
                              operation: "query",
                              sha256Hash: SEARCH_HASH,
                              value: null
                          }, {
                              searchTerm: `artist:"${safeArtistName}" year:${slice}`,
                              offset: offset,
                              limit: limit,
                              numberOfTopResults: limit,
                              includePreReleases: false
                          });

                          const tracks = res?.data?.searchV2?.tracksV2?.items || [];
                          if (tracks.length === 0) break;

                          tracks.forEach(tNode => {
                              const t = tNode.item?.data;
                              if (t && t.albumOfTrack && t.albumOfTrack.uri) {
                                  const trackArtists = t.artists?.items || [];
                                  const hasTargetArtist = trackArtists.some(a => a.uri && a.uri.includes(targetArtistId));
                                  
                                  if (hasTargetArtist) {
                                      const id = t.albumOfTrack.uri.split(':')[2];
                                      if (!allAlbumMetadata.has(id)) {
                                          allAlbumMetadata.set(id, { 
                                              type: 'appears_on', 
                                              date: null 
                                          });
                                      }
                                  }
                              }
                          });

                          if (tracks.length < limit) break;
                          offset += limit;
                      } catch (e) {
                          break;
                      }
                  }
              }));
              await new Promise(r => setTimeout(r, 50));
          }
      };

      await Promise.all([fetchAlbumIdsGQL(), fetchAppearsOnIdsGQL()]);
      const searchPromise = fetchAppearsOnViaSearch();
  
      const allTracks = [];
      let isHeavyweight = false;
      let fetchedAlbumsCount = 0;

      const fetchTracks = async (albumIdsToProcess) => {
          const targetArtistId = artistUri.split(':')[2];
          
          if (!isHeavyweight && albumIdsToProcess.length > 1000) {
              isHeavyweight = true;
          }

          let startIndex = 0;
          const incrementAlbumCount = () => {
              fetchedAlbumsCount++;
              if (progressCallback) progressCallback(`Rel. ${fetchedAlbumsCount}`);
              else if (!isHeadless) mainButton.innerText = `Rel. ${fetchedAlbumsCount}`;
          };

          if (!isHeavyweight && albumIdsToProcess.length > 0) {
              const sniffBatchSize = Math.min(50, albumIdsToProcess.length);
              const sniffBatch = albumIdsToProcess.slice(0, sniffBatchSize);
              startIndex = sniffBatchSize;

              const promises = sniffBatch.map(async (id) => {
                  const meta = allAlbumMetadata.get(id);
                  try {
                      const tracks = await getAlbumTracks(id, meta.date, false);
                      
                      const filtered = tracks.filter(track => track.artistUris && track.artistUris.some(uri => uri && uri.includes(targetArtistId)))
                          .map(track => {
                              if (track.track && track.track.album) track.track.album.album_type = meta.type;
                              return { ...track, albumType: meta.type, album_type: meta.type };
                          });
                      return { filtered, totalInAlbum: tracks.length };
                  } finally {
                      incrementAlbumCount();
                  }
              });

              const results = await Promise.all(promises);
              let sniffTotalTracks = 0;
              results.forEach(res => {
                  allTracks.push(...res.filtered);
                  sniffTotalTracks += res.totalInAlbum;
              });

              const avgTracksPerAlbum = sniffTotalTracks / sniffBatchSize;
              const estimatedTotalTracks = avgTracksPerAlbum * albumIdsToProcess.length;
              
              if (estimatedTotalTracks > 12000) {
                  isHeavyweight = true;
              }
          }

          const remainingIds = albumIdsToProcess.slice(startIndex);
          if (remainingIds.length === 0) return;

          if (isHeavyweight) {
              const CONCURRENCY_LIMIT = 30;
              const queue = [...remainingIds];
              let currentIndex = 0;
              const worker = async () => {
                  while (currentIndex < queue.length) {
                      const id = queue[currentIndex++];
                      const meta = allAlbumMetadata.get(id);
                      try {
                          const tracks = await getAlbumTracks(id, meta.date, true);
                          const filteredTracks = tracks.filter(track => track.artistUris && track.artistUris.some(uri => uri && uri.includes(targetArtistId)))
                              .map(track => {
                                  if (track.track && track.track.album) track.track.album.album_type = meta.type;
                                  return { ...track, albumType: meta.type, album_type: meta.type };
                              });
                          allTracks.push(...filteredTracks);
                      } catch (e) {
                          console.warn(`[Sort-Play] Failed to process album ${id} in queue`, e);
                      } finally {
                          incrementAlbumCount();
                      }
                  }
              };
              const workers = Array(Math.min(CONCURRENCY_LIMIT, remainingIds.length)).fill(null).map(() => worker());
              await Promise.all(workers);
          } else {
              const BATCH_SIZE = 50;
              for (let i = 0; i < remainingIds.length; i += BATCH_SIZE) {
                  const batch = remainingIds.slice(i, i + BATCH_SIZE);
                  const promises = batch.map(async (id) => {
                      const meta = allAlbumMetadata.get(id);
                      try {
                          const tracks = await getAlbumTracks(id, meta.date, false);
                          return tracks.filter(track => track.artistUris && track.artistUris.some(uri => uri && uri.includes(targetArtistId)))
                              .map(track => {
                                  if (track.track && track.track.album) track.track.album.album_type = meta.type;
                                  return { ...track, albumType: meta.type, album_type: meta.type };
                              });
                      } finally {
                          incrementAlbumCount();
                      }
                  });
                  const results = await Promise.all(promises);
                  results.forEach(tracks => { if (tracks) allTracks.push(...tracks); });
              }
          }
      };

      const initialAlbumIds = Array.from(allAlbumMetadata.keys());
      await fetchTracks(initialAlbumIds);

      await searchPromise;

      const newAlbumIds = Array.from(allAlbumMetadata.keys()).filter(id => !initialAlbumIds.includes(id));
      if (newAlbumIds.length > 0) {
          await fetchTracks(newAlbumIds);
      }

      if (progressCallback) progressCallback("Checking...");
      const allTracksRefreshed = await refreshTrackAlbumInfo(allTracks, () => {});

      const uniqueTracksMap = new Map();
      for (const track of allTracksRefreshed) {
          if (!uniqueTracksMap.has(track.uri)) {
              uniqueTracksMap.set(track.uri, track);
          }
      }

      return Array.from(uniqueTracksMap.values());
  
    } catch (error) {
      console.error("Error fetching artist tracks:", error);
      throw error;
    }
  }

  async function getArtistTracksForShuffle(artistUri) {
    const { Locale, GraphQL, CosmosAsync } = Spicetify;
  
    const queryArtistOverview = Spicetify.GraphQL.Definitions.queryArtistOverview || {
      name: "queryArtistOverview",
      operation: "query",
      sha256Hash: "35648a112beb1794e39ab931365f6ae4a8d45e65396d641eeda94e4003d41497",
    };
  
    try {
      const artistData = await GraphQL.Request(queryArtistOverview, {
        uri: artistUri,
        locale: Locale.getLocale(),
        includePrerelease: false,
      });
  
      if (artistData.errors) throw new Error(artistData.errors[0].message);
      const artistName = artistData.data.artistUnion.profile.name;

      const allAlbumMetadata = new Map();

      const fetchAlbumIdsGQL = async () => {
          let offset = 0;
          let limit = 100;
          let total = null;
          while (total === null || offset < total) {
              try {
                  const res = await GraphQL.Request(GraphQL.Definitions.queryArtistDiscographyAll, {
                      uri: artistUri,
                      offset: offset,
                      limit: limit
                  });
                  const disc = res?.data?.artistUnion?.discography?.all;
                  if (!disc) break;
                  total = disc.totalCount;
                  disc.items.forEach(group => {
                      if (group.releases && group.releases.items) {
                          group.releases.items.forEach(rel => {
                              const id = rel.uri.split(':')[2];
                              allAlbumMetadata.set(id, { 
                                  type: rel.type || 'album',
                                  date: rel.date?.isoString || rel.date?.year 
                              });
                          });
                      }
                  });
                  offset += limit;
              } catch (e) {
                  console.warn("fetchAlbumIdsGQL failed for shuffle", e);
                  break;
              }
          }
      };

      const fetchAppearsOnIdsGQL = async () => {
          let offset = 0;
          let limit = 100;
          let total = null;
          while (total === null || offset < total) {
              try {
                  const res = await GraphQL.Request(GraphQL.Definitions.queryArtistAppearsOn, {
                      uri: artistUri,
                      offset: offset,
                      limit: limit
                  });
                  const appearsOn = res?.data?.artistUnion?.relatedContent?.appearsOn;
                  if (!appearsOn) break;
                  
                  total = appearsOn.totalCount;
                  
                  if (appearsOn.items) {
                      appearsOn.items.forEach(item => {
                          const release = item.releases?.items?.[0];
                          if (release) {
                              const id = release.uri.split(':')[2];
                              if (!allAlbumMetadata.has(id)) {
                                  allAlbumMetadata.set(id, { 
                                      type: 'appears_on'
                                  });
                              }
                          }
                      });
                  }
                  offset += limit;
              } catch (e) {
                  break;
              }
          }
      };

      const fetchAppearsOnViaSearch = async () => {
          if (artistName.toLowerCase() === "various artists") return;
          
          const SEARCH_HASH = "131fd38c13431be963a851082dca0108a4200998b886e7e9d20a21fc51a36aaf";
          const currentYear = new Date().getFullYear();
          const timeSlices = ["0-1989", "1990-1999"];
          for (let y = 2000; y <= currentYear + 1; y++) {
              timeSlices.push(y.toString());
          }

          const safeArtistName = artistName.replace(/"/g, '\\"');
          const BATCH_SIZE = 30;
          const targetArtistId = artistUri.split(':')[2];
          
          for (let i = 0; i < timeSlices.length; i += BATCH_SIZE) {
              const batch = timeSlices.slice(i, i + BATCH_SIZE);
              await Promise.all(batch.map(async (slice) => {
                  let offset = 0;
                  let limit = 50;
                  while (offset < 1000) {
                      try {
                          const res = await GraphQL.Request({
                              name: "searchTracks",
                              operation: "query",
                              sha256Hash: SEARCH_HASH,
                              value: null
                          }, {
                              searchTerm: `artist:"${safeArtistName}" year:${slice}`,
                              offset: offset,
                              limit: limit,
                              numberOfTopResults: limit,
                              includePreReleases: false
                          });

                          const tracks = res?.data?.searchV2?.tracksV2?.items || [];
                          if (tracks.length === 0) break;

                          tracks.forEach(tNode => {
                              const t = tNode.item?.data;
                              if (t && t.albumOfTrack && t.albumOfTrack.uri) {
                                  const trackArtists = t.artists?.items || [];
                                  const hasTargetArtist = trackArtists.some(a => a.uri && a.uri.includes(targetArtistId));
                                  
                                  if (hasTargetArtist) {
                                      const id = t.albumOfTrack.uri.split(':')[2];
                                      if (!allAlbumMetadata.has(id)) {
                                          allAlbumMetadata.set(id, { 
                                              type: 'appears_on'
                                          });
                                      }
                                  }
                              }
                          });

                          if (tracks.length < limit) break;
                          offset += limit;
                      } catch (e) {
                          break;
                      }
                  }
              }));
              await new Promise(r => setTimeout(r, 50));
          }
      };

      await Promise.all([fetchAlbumIdsGQL(), fetchAppearsOnIdsGQL()]);
      const searchPromise = fetchAppearsOnViaSearch();
  
      const allTracks = [];
      let isHeavyweight = false;
      let fetchedAlbumsCount = 0;

      const fetchTracks = async (albumIdsToProcess) => {
          const targetArtistId = artistUri.split(':')[2];
          
          if (!isHeavyweight && albumIdsToProcess.length > 1000) {
              isHeavyweight = true;
          }

          let startIndex = 0;
          const incrementAlbumCount = () => {
              fetchedAlbumsCount++;
              mainButton.innerText = `Rel. ${fetchedAlbumsCount}`;
          };

          if (!isHeavyweight && albumIdsToProcess.length > 0) {
              const sniffBatchSize = Math.min(50, albumIdsToProcess.length);
              const sniffBatch = albumIdsToProcess.slice(0, sniffBatchSize);
              startIndex = sniffBatchSize;

              const promises = sniffBatch.map(async (id) => {
                  const meta = allAlbumMetadata.get(id);
                  try {
                      const tracks = await getAlbumTracks(id, meta.date, false);
                      
                      const filtered = tracks.filter(track => track.artistUris && track.artistUris.some(uri => uri && uri.includes(targetArtistId)))
                          .map(track => ({ ...track, album_type: meta.type || 'album' }));
                      return { filtered, totalInAlbum: tracks.length };
                  } finally {
                      incrementAlbumCount();
                  }
              });

              const results = await Promise.all(promises);
              let sniffTotalTracks = 0;
              results.forEach(res => {
                  allTracks.push(...res.filtered);
                  sniffTotalTracks += res.totalInAlbum;
              });

              const avgTracksPerAlbum = sniffTotalTracks / sniffBatchSize;
              const estimatedTotalTracks = avgTracksPerAlbum * albumIdsToProcess.length;
              
              if (estimatedTotalTracks > 12000) {
                  isHeavyweight = true;
              }
          }

          const remainingIds = albumIdsToProcess.slice(startIndex);
          if (remainingIds.length === 0) return;

          if (isHeavyweight) {
              const CONCURRENCY_LIMIT = 30;
              const queue = [...remainingIds];
              let currentIndex = 0;
              const worker = async () => {
                  while (currentIndex < queue.length) {
                      const id = queue[currentIndex++];
                      const meta = allAlbumMetadata.get(id);
                      try {
                          const tracks = await getAlbumTracks(id, meta.date, true);
                          const filteredTracks = tracks.filter(track => track.artistUris && track.artistUris.some(uri => uri && uri.includes(targetArtistId)))
                              .map(track => ({ ...track, album_type: meta.type || 'album' }));
                          allTracks.push(...filteredTracks);
                      } catch (e) {
                          console.warn(`[Sort-Play] Failed to process album ${id} in shuffle queue`, e);
                      } finally {
                          incrementAlbumCount();
                      }
                  }
              };
              const workers = Array(Math.min(CONCURRENCY_LIMIT, remainingIds.length)).fill(null).map(() => worker());
              await Promise.all(workers);
          } else {
              const BATCH_SIZE = 50;
              for (let i = 0; i < remainingIds.length; i += BATCH_SIZE) {
                  const batch = remainingIds.slice(i, i + BATCH_SIZE);
                  const promises = batch.map(async (id) => {
                      const meta = allAlbumMetadata.get(id);
                      try {
                          const tracks = await getAlbumTracks(id, meta.date, false);
                          return tracks.filter(track => track.artistUris && track.artistUris.some(uri => uri && uri.includes(targetArtistId)))
                              .map(track => ({ ...track, album_type: meta.type || 'album' }));
                      } finally {
                          incrementAlbumCount();
                      }
                  });
                  const results = await Promise.all(promises);
                  results.forEach(tracks => { if (tracks) allTracks.push(...tracks); });
              }
          }
      };

      const initialAlbumIds = Array.from(allAlbumMetadata.keys());
      await fetchTracks(initialAlbumIds);

      await searchPromise;

      const newAlbumIds = Array.from(allAlbumMetadata.keys()).filter(id => !initialAlbumIds.includes(id));
      if (newAlbumIds.length > 0) {
          await fetchTracks(newAlbumIds);
      }
  
      const uniqueTracksMap = new Map();
      const isCoreDiscography = (track) => 
          track.album_type === 'album' || track.album_type === 'single';

      for (const track of allTracks) {
        const title = (track.name || "").toLowerCase().trim();
        const duration = Math.round(track.durationMilis / 1000);
        const artistKey = (track.artistUris || []).sort().join(',');
        const compositeKey = `${title}|${duration}|${artistKey}`;

        const existingTrack = uniqueTracksMap.get(compositeKey);

        if (!existingTrack) {
            uniqueTracksMap.set(compositeKey, track);
        } else {
            if (isCoreDiscography(track) && !isCoreDiscography(existingTrack)) {
                uniqueTracksMap.set(compositeKey, track);
            }
        }
      }

      const uniqueTracks = Array.from(uniqueTracksMap.values());
  
      return uniqueTracks;
  
    } catch (error) {
      console.error("Error fetching artist tracks for shuffle:", error);
      throw error;
    }
  }

  async function getArtistImageUrl(artistId) {
    const fetchGQL = async () => {
        const res = await Spicetify.GraphQL.Request(Spicetify.GraphQL.Definitions.queryArtistOverview, {
            uri: `spotify:artist:${artistId}`,
            locale: "en",
            includePrerelease: false
        });
        
        const sources = res.data.artistUnion.visuals.avatarImage?.sources;
        if (!sources || sources.length === 0) return null;

        const bestSource = sources.reduce((prev, curr) => (prev.width > curr.width ? prev : curr));
        return bestSource.url;
    };

    try { return await fetchGQL(); } catch(e) { return null; }
  }
  
  function setPlaylistImage(playlistId, base64Image, maxRetries = 10, retryInterval = 4000) {
    (async () => {
        const playlistUri = `spotify:playlist:${playlistId}`;

        const setInternalImage = async () => {
            const bufferToHex = (buffer) => Array.from(new Uint8Array(buffer)).map(b => b.toString(16).padStart(2, '0')).join('');
            const getFileFromBase64 = async (b64) => {
                const res = await fetch(b64);
                const blob = await res.blob();
                return new File([blob], "cover.jpg", { type: "image/jpeg" });
            };

            const file = await getFileFromBase64(base64Image);
            const uploadToken = await Spicetify.Platform.PlaylistAPI.uploadImage(file);
            
            if (!uploadToken) throw new Error("Upload failed: No token returned");

            let regRes = null;
            let attempt = 0;
            while (attempt < 3) {
                if (internalTokenRefreshPromise) await internalTokenRefreshPromise;
                const sessionToken = Spicetify.Platform.Session.accessToken;
                
                regRes = await fetch(`https://spclient.wg.spotify.com/playlist/v2/playlist/${playlistId}/register-image`, {
                    method: 'POST',
                    headers: {
                        'Authorization': `Bearer ${sessionToken}`,
                        'Content-Type': 'application/json'
                    },
                    body: JSON.stringify({ uploadToken })
                });

                if (regRes.status === 401) {
                    if (!internalTokenRefreshPromise) {
                        internalTokenRefreshPromise = (async () => {
                            try {
                                const tData = await Spicetify.CosmosAsync.get('sp://auth/v2/token');
                                Spicetify.Platform.Session.accessToken = tData.accessToken;
                                await new Promise(r => setTimeout(r, 500));
                                return tData.accessToken;
                            } catch(e) { throw e; } finally { internalTokenRefreshPromise = null; }
                        })();
                    }
                    try { await internalTokenRefreshPromise; } catch(e) { break; }
                    attempt++;
                    continue;
                }
                break;
            }

            if (!regRes || !regRes.ok) throw new Error(`Registration failed: ${regRes?.status}`);

            const buffer = await regRes.arrayBuffer();
            const fullHex = bufferToHex(buffer);
            const cleanHexId = fullHex.startsWith('0a14') ? fullHex.slice(4) : fullHex;

            await Spicetify.Platform.PlaylistAPI.setAttributes(playlistUri, { picture: cleanHexId });
            if (typeof Spicetify.Platform.PlaylistAPI.resync === 'function') await Spicetify.Platform.PlaylistAPI.resync(playlistUri);
        };

        for (let attempt = 1; attempt <= maxRetries; attempt++) {
            try {
                await setInternalImage();

                await new Promise(resolve => setTimeout(resolve, 1500));

                const meta = await Spicetify.Platform.PlaylistAPI.getMetadata(playlistUri);
                if (meta && meta.images && meta.images.length > 0 && !isDefaultMosaicCover(meta.images[0].url)) {
                    return;
                }
                
                throw new Error("Verification failed: Image not updated on Spotify side yet.");

            } catch (error) {                
                if (attempt < maxRetries) {
                    await new Promise(resolve => setTimeout(resolve, retryInterval));
                } else {
                    console.error(`[Sort-Play] Failed to set and verify playlist image for ${playlistId} after ${maxRetries} attempts.`, error);
                }
            }
        }
    })();
  }

  async function imageUrlToBase64(url) {
    if (typeof url === 'string') {
        if (url.startsWith("spotify:image:")) {
            const imageId = url.split(":")[2];
            url = `https://i.scdn.co/image/${imageId}`;
        } else if (url.startsWith("spotify:")) {
            throw new Error("Unsupported URI scheme for image fetch");
        }
    }

    const response = await fetch(url);
    const blob = await response.blob();
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result);
        reader.onerror = reject;
        reader.readAsDataURL(blob);
    });
  }
  
  async function toBase64(imageUrl) {
    if (imageUrl.startsWith('spotify:')) {
        return Promise.reject(new Error("Cannot convert spotify: URIs to base64 using canvas"));
    }
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = "Anonymous";
      img.onload = () => {
        const canvas = document.createElement("canvas");
        const ctx = canvas.getContext("2d");
        const size = 640;
        canvas.width = size;
        canvas.height = size;

        const sourceWidth = img.naturalWidth;
        const sourceHeight = img.naturalHeight;

        const cropSize = Math.min(sourceWidth, sourceHeight);
        const sx = (sourceWidth - cropSize) / 2;
        const sy = (sourceHeight - cropSize) / 2;

        ctx.drawImage(img, sx, sy, cropSize, cropSize, 0, 0, size, size);

        const dataUrl = canvas.toDataURL("image/jpeg"); 
        resolve(dataUrl);
      };
      img.onerror = (error) => reject(error);
      img.src = imageUrl;
    });
  }

  async function getUnifiedAlbumData(albumId, retries = 10, retryDelay = 2000) {
    if (albumDataCache[albumId] && albumReleaseDateCache[albumId] !== undefined) {
      return { playCounts: albumDataCache[albumId], releaseDate: albumReleaseDateCache[albumId] };
    }

    if (!inFlightAlbumRequests[albumId]) {
      inFlightAlbumRequests[albumId] = new Promise(async (resolve, reject) => {
        const { Locale, GraphQL } = Spicetify;

        for (let attempt = 1; attempt <= retries; attempt++) {
          try {
            const promise = GraphQL.Request(GraphQL.Definitions.getAlbum, {
              uri: `spotify:album:${albumId}`,
              locale: Locale.getLocale(),
              offset: 0,
              limit: 500,
            });
            const res = await Promise.race([
              promise,
              new Promise((_, reject) => setTimeout(() => reject(new Error("Timeout")), 10000))
            ]);

            if (!res.data?.albumUnion) {
              throw new Error(`No albumUnion in response for album ID: ${albumId}`);
            }

            const u = res.data.albumUnion;
            
            let releaseDate = 0;
            if (u.date) {
              if (u.date.isoString) releaseDate = new Date(u.date.isoString).getTime();
              else if (u.date.year) releaseDate = new Date(u.date.year.toString()).getTime();
            }
            albumReleaseDateCache[albumId] = releaseDate;

            const tracks = u.tracksV2?.items || u.tracks?.items || [];
            const albumTracks = [];
            const entriesToSave = [];
            
            tracks.forEach((item) => {
              const track = item.track;
              if (!track) return;
              const tNum = parseInt(track.trackNumber || track.track_number, 10) || 0;
              const pCount = parseInt(track.playcount, 10) || 0;
              const tId = track.uri.split(":")[2];
              
              entriesToSave.push({ key: tId, val: { date: releaseDate, trackNumber: tNum } });

              albumTracks.push({
                uri: track.uri,
                name: track.name,
                trackNumber: tNum,
                playcount: pCount,
                releaseDate: releaseDate
              });
            });
            
            if (idb.setMany && entriesToSave.length > 0) {
                idb.setMany('releaseDates', entriesToSave).catch(() => {});
            }

            albumDataCache[albumId] = albumTracks;
            albumTracksDataCache[albumId] = albumTracks;

            resolve({ playCounts: albumTracks, releaseDate });
            return;
          } catch (error) {
            if (attempt < retries) {
              await new Promise(r => setTimeout(r, retryDelay));
              retryDelay *= 2;
            } else {
              reject(error);
              return;
            }
          }
        }
      });
    }

    try {
      return await inFlightAlbumRequests[albumId];
    } catch (error) {
      console.error(`Final failure for unified album ID ${albumId}:`, error);
      return { playCounts: [], releaseDate: null };
    } finally {
      setTimeout(() => delete inFlightAlbumRequests[albumId], 500);
    }
  }

  async function getPlayCountsForAlbum(albumId) {
    const data = await getUnifiedAlbumData(albumId);
    return data.playCounts || [];
  }

  async function getReleaseDatesForAlbum(albumId) {
    const data = await getUnifiedAlbumData(albumId);
    return data.releaseDate;
  }

  async function getTrackDetailsWithPlayCount(track, retries = 10, retryDelay = 1000) {
    const trackId = track.trackId || track.id || track.track?.id;
    const albumId = track.albumId || track.album?.id || track.track?.album?.id;

    if (!trackId) return track;

    const cachedCount = await idb.get('playCounts', trackId, CACHE_EXPIRE_PLAYCOUNTS);
    
    if (cachedCount !== null && cachedCount !== undefined && cachedCount !== "N/A") {
        return {
            ...track,
            playCount: cachedCount,
            songTitle: track.songTitle || track.name,
            albumName: track.albumName || track.album?.name || track.track?.album?.name || "Unknown Album",
            trackId: trackId,
            albumId: albumId,
            uri: track.uri || `spotify:track:${trackId}`,
            artistName: track.artistName,
            allArtists: track.allArtists
        };
    }

    try {
      let playCount = "N/A";
      let trackNumber = track.trackNumber || track.track?.track_number || track.track?.trackNumber || 0;

      try {
          const resMap = await fetchPlayCountsBatchNew([`spotify:track:${trackId}`]);
          const pc = resMap.get(`spotify:track:${trackId}`);
          if (pc !== undefined) {
              playCount = pc;
              await idb.set('playCounts', trackId, playCount);
          }
      } catch (e) {
          console.warn("[Sort-Play] New playcount fetch failed for single track", e);
      }

      if (playCount === "N/A" && albumId) {
          const albumTracksWithPlayCounts = await getPlayCountsForAlbum(albumId);
          const foundTrack = albumTracksWithPlayCounts.find(
            (albumTrack) => albumTrack.uri === `spotify:track:${trackId}`
          );

          if (foundTrack) {
            playCount = foundTrack.playcount;
            trackNumber = foundTrack.trackNumber;
            if (playCount !== "N/A") {
                await idb.set('playCounts', trackId, playCount);
            }
          }
      }

      if ((playCount === "N/A" || playCount === undefined) && Spicetify.GraphQL.Definitions.getTrack) {
          try {
              const res = await Spicetify.GraphQL.Request(Spicetify.GraphQL.Definitions.getTrack, { uri: `spotify:track:${trackId}` });
              if (res?.data?.trackUnion?.playcount) {
                  const pc = parseInt(res.data.trackUnion.playcount, 10);
                  if (!isNaN(pc)) {
                      playCount = pc;
                      await idb.set('playCounts', trackId, playCount);
                  }
              }
          } catch (e) {
              console.warn("[Sort-Play] GraphQL single playcount fallback failed", e);
          }
      }

      return {
        ...track,
        trackNumber: trackNumber,
        songTitle: track.songTitle || track.name, 
        albumName: track.albumName || track.album?.name || track.track?.album?.name || "Unknown Album",
        trackId: trackId,
        albumId: albumId,
        durationMs: track.durationMs || track.track?.duration_ms,
        playCount: playCount,
        uri: track.uri || `spotify:track:${trackId}`,
        artistName: track.artistName,
        allArtists: track.allArtists,
      };
    } catch (error) {
      console.error(`Error getting details for track ${track.name}:`, error);
      if (retries > 0) {
        await new Promise((resolve) => setTimeout(resolve, retryDelay));
        return getTrackDetailsWithPlayCount(track, retries - 1, retryDelay * 2);
      }
      return { ...track, playCount: "N/A" };
    }
  }

  async function enrichTracksWithPlayCounts(tracks, updateProgress = () => {}) {
    const tracksWithIds = tracks.map(t => {
        const isLocal = Spicetify.URI.isLocal(t.uri);
        const id = isLocal ? null : (t.trackId || t.id || t.track?.id || (t.uri ? t.uri.split(':')[2] : null));
        const albumId = isLocal ? null : (t.albumId || t.album?.id || t.track?.album?.id);
        return { ...t, _tempId: id, _tempAlbumId: albumId, _isLocal: isLocal };
    });

    const trackIdsToCheck = tracksWithIds.map(t => t._tempId).filter(Boolean);
    const cachedPlayCounts = await idb.getMany('playCounts', trackIdsToCheck, CACHE_EXPIRE_PLAYCOUNTS);

    const playCountMap = new Map(); 
    const missingUris = [];
    const missingTracks = [];

    tracksWithIds.forEach(track => {
        if (!track._tempId) return;
        const cachedVal = cachedPlayCounts.get(track._tempId);
        if (cachedVal !== undefined && cachedVal !== null && cachedVal !== "N/A") {
            playCountMap.set(track._tempId, cachedVal);
        } else {
            missingUris.push(`spotify:track:${track._tempId}`);
            missingTracks.push(track);
        }
    });

    const uniqueMissingUris = [...new Set(missingUris)];

    if (uniqueMissingUris.length > 0) {
        try {
            const BATCH_SIZE = 3000;
            const DELAY = 100;
            let processedTracks = 0;
            
            for (let i = 0; i < uniqueMissingUris.length; i += BATCH_SIZE) {
                const batch = uniqueMissingUris.slice(i, i + BATCH_SIZE);
                const batchResults = await fetchPlayCountsBatchNew(batch);
                const entriesToSave = [];
                
                for (const [uri, count] of batchResults.entries()) {
                    const tId = uri.split(":")[2];
                    playCountMap.set(tId, count);
                    entriesToSave.push({ key: tId, val: count });
                }
                
                if (idb.setMany && entriesToSave.length > 0) {
                    await idb.setMany('playCounts', entriesToSave);
                }
                
                processedTracks += batch.length;
                if (updateProgress) {
                    updateProgress(Math.floor((processedTracks / uniqueMissingUris.length) * 100));
                }
                
                if (i + BATCH_SIZE < uniqueMissingUris.length) {
                    await new Promise(r => setTimeout(r, DELAY));
                }
            }
        } catch (e) {
            console.warn("[Sort-Play] New playcount fetch method failed, falling back to album parsing", e);
        }

        const stillMissingTracks = missingTracks.filter(track => !playCountMap.has(track._tempId));

        if (stillMissingTracks.length > 0) {
            const albumGroups = new Map();
            stillMissingTracks.forEach(track => {
                if (track._tempAlbumId) {
                    if (!albumGroups.has(track._tempAlbumId)) {
                        albumGroups.set(track._tempAlbumId, []);
                    }
                    albumGroups.get(track._tempAlbumId).push(track);
                }
            });

            const uniqueAlbumIds = Array.from(albumGroups.keys());
            if (uniqueAlbumIds.length > 0) {
                let processedAlbums = 0;
                const totalAlbums = uniqueAlbumIds.length;
                
                let CONCURRENCY_LIMIT = 6;
                if (totalAlbums <= 50) {
                    CONCURRENCY_LIMIT = 15;
                } else if (totalAlbums <= 400) {
                    CONCURRENCY_LIMIT = 10;
                } else if (totalAlbums <= 1000) {
                    CONCURRENCY_LIMIT = 8;
                }

                async function worker(queue) {
                    while (queue.length > 0) {
                        const albumId = queue.shift();
                        try {
                            const albumTracks = await getPlayCountsForAlbum(albumId);
                            
                            albumTracks.forEach(t => {
                                const tId = t.uri.split(":")[2];
                                if (t.playcount !== undefined && t.playcount !== "N/A") {
                                    playCountMap.set(tId, t.playcount);
                                    idb.set('playCounts', tId, t.playcount); 
                                }
                            });
                        } catch (error) {
                            console.error(`Failed to process album ${albumId}`, error);
                        } finally {
                            processedAlbums++;
                            if (totalAlbums > 0 && updateProgress) {
                                updateProgress(Math.floor((processedAlbums / totalAlbums) * 100));
                            }
                        }
                    }
                }

                const queue = [...uniqueAlbumIds];
                const workers = Array(Math.min(CONCURRENCY_LIMIT, uniqueAlbumIds.length)).fill(null).map(() => worker(queue));
                await Promise.all(workers);
            }
        }

        const finalMissingTracks = stillMissingTracks.filter(track => !playCountMap.has(track._tempId));
        if (finalMissingTracks.length > 0 && Spicetify.GraphQL.Definitions.getTrack) {
            const GQL_CONCURRENCY = 10;
            const gqlQueue = [...finalMissingTracks];
            
            let currentIndex = 0;
            async function gqlWorker() {
                const entriesToSave = [];
                while (currentIndex < gqlQueue.length) {
                    const track = gqlQueue[currentIndex++];
                    const uri = `spotify:track:${track._tempId}`;
                    try {
                        const res = await Spicetify.GraphQL.Request(Spicetify.GraphQL.Definitions.getTrack, { uri });
                        if (res?.data?.trackUnion?.playcount) {
                            const pc = parseInt(res.data.trackUnion.playcount, 10);
                            if (!isNaN(pc)) {
                                playCountMap.set(track._tempId, pc);
                                entriesToSave.push({ key: track._tempId, val: pc });
                            }
                        }
                    } catch (e) {}
                }
                if (idb.setMany && entriesToSave.length > 0) {
                    await idb.setMany('playCounts', entriesToSave);
                }
            }
            
            const gqlWorkers = Array(Math.min(GQL_CONCURRENCY, finalMissingTracks.length)).fill(null).map(() => gqlWorker());
            await Promise.all(gqlWorkers);
        }
    } else {
        if (updateProgress) updateProgress(100);
    }

    const enrichedTracks = tracks.map(track => {
        const isLocal = Spicetify.URI.isLocal(track.uri);
        const albumId = isLocal ? null : (track.albumId || track.album?.id || track.track?.album?.id);
        const trackId = isLocal ? null : (track.trackId || track.id || track.track?.id || (track.uri ? track.uri.split(':')[2] : null));
        const duration = track.durationMs || track.durationMilis || track.duration_ms || track.track?.duration_ms || 0;

        if (!trackId || isLocal) {
            return { 
                ...track, 
                playCount: "N/A", 
                trackNumber: 0,
                songTitle: track.name || track.songTitle || "Unknown Title",
                trackId: trackId,
                albumId: albumId,
                durationMs: duration,
                uri: track.uri || (trackId ? `spotify:track:${trackId}` : undefined)
            };
        }

        const playCount = playCountMap.has(trackId) ? playCountMap.get(trackId) : "N/A";

        const enrichedData = {
            trackNumber: track.trackNumber || track.track_number || 0,
            songTitle: track.songTitle || track.name,
            albumName: track.albumName || track.album?.name || track.track?.album?.name || "Unknown Album",
            trackId: trackId,
            albumId: albumId,
            durationMs: duration,
            playcount: playCount,
            playCount: playCount,
            uri: track.uri || `spotify:track:${trackId}`,
            artistName: track.artistName || track.artists?.[0]?.name,
            allArtists: track.allArtists || track.artists?.map(a => a.name).join(", "),
        };
        
        return { ...track, ...enrichedData };
    });

    return enrichedTracks;
  }

  async function refreshTrackAlbumInfo(tracks, updateProgress = () => {}) {
      const validUris = [];
      const uniqueIds = new Set();

      tracks.forEach(t => {
          if (!Spicetify.URI.isLocal(t.uri) && t.uri.startsWith('spotify:track:')) {
              const id = t.id || t.track?.id || t.uri.split(':')[2];
              if (!uniqueIds.has(id)) {
                  uniqueIds.add(id);
                  validUris.push(t.uri);
              }
          }
      });

      let fetchedData = new Map();
      if (validUris.length > 0) {
          try {
              fetchedData = await fetchCoreMetadataBatch(validUris);
          } catch (e) {
              console.warn("[Sort-Play] Fast batch metadata fetch failed in refreshTrackAlbumInfo", e);
          }
      }

      updateProgress(100);

      return tracks.map(track => {
          if (Spicetify.URI.isLocal(track.uri) || !track.uri.startsWith('spotify:track:')) {
              track.albumType = 'album';
              track.album_type = 'album';
              if (track.track && track.track.album) track.track.album.album_type = 'album';
              return track;
          }

          const meta = fetchedData.get(track.uri);
          if (meta) {
              const accurateType = meta.albumType || 'album';
              const result = {
                  ...track,
                  albumType: accurateType,
                  album_type: accurateType,
                  _hasAccurateType: true
              };
              
              if (result.track && result.track.album) {
                  result.track.album.album_type = accurateType;
              }
              
              if (meta.releaseDate && !result.releaseDate) {
                  result.releaseDate = meta.releaseDate;
              }
              
              if (meta.isrc) {
                  if (!result.track) result.track = {};
                  if (!result.track.external_ids) result.track.external_ids = {};
                  result.track.external_ids.isrc = meta.isrc;
              }
              
              return result;
          }

          const fallbackType = track.albumType || track.album_type || track.track?.album?.album_type || 'album';
          track.albumType = fallbackType;
          track.album_type = fallbackType;
          if (track.track && track.track.album) track.track.album.album_type = fallbackType;
          return track;
      });
  }
  
  async function processReleaseDatesConcurrently(tracks, updateProgress = () => {}, fetchFunction = getTrackDetailsWithReleaseDate) {
    const trackIds = tracks.map(t => t.trackId || (t.uri ? t.uri.split(':')[2] : null)).filter(Boolean);
    const cachedMap = await idb.getMany('releaseDates', trackIds, CACHE_EXPIRE_RELEASE_DATE);
    
    const missingUris = [];
    const results = new Array(tracks.length);
    
    tracks.forEach((track, index) => {
        if (Spicetify.URI.isLocal(track.uri)) {
            results[index] = { ...track, releaseDate: null, trackNumber: track.trackNumber || 0 };
            return;
        }
        const trackId = track.trackId || (track.uri ? track.uri.split(':')[2] : null);
        let cached = trackId ? cachedMap.get(trackId) : null;
        
        if (cached && typeof cached === 'object' && cached.trackNumber !== undefined) {
            results[index] = { ...track, releaseDate: cached.date, trackNumber: cached.trackNumber };
        } else {
            missingUris.push({ track, index, trackId });
        }
    });

    if (missingUris.length > 0) {
        const BATCH_SIZE = 1000;
        let processedCount = 0;
        
        for (let i = 0; i < missingUris.length; i += BATCH_SIZE) {
            const batch = missingUris.slice(i, i + BATCH_SIZE);
            const urisToFetch = batch.map(b => b.track.uri);
            
            try {
                const fetchedMetaMap = await fetchCoreMetadataBatch(urisToFetch);
                const entriesToSave = [];
                
                for (const item of batch) {
                    const { track, index, trackId } = item;
                    const meta = fetchedMetaMap.get(track.uri);
                    
                    if (meta && meta.releaseDate) {
                        results[index] = { ...track, releaseDate: meta.releaseDate, trackNumber: track.trackNumber || 0 };
                        if (trackId) {
                            entriesToSave.push({ key: trackId, val: { date: meta.releaseDate, trackNumber: track.trackNumber || 0 } });
                        }
                    } else {
                        results[index] = await fetchFunction(track);
                    }
                }
                
                if (idb.setMany && entriesToSave.length > 0) {
                    await idb.setMany('releaseDates', entriesToSave);
                }
            } catch (e) {
                console.warn("[Sort-Play] Batch core metadata fetch failed, falling back", e);
                for (const item of batch) {
                    results[item.index] = await fetchFunction(item.track);
                }
            }
            
            processedCount += batch.length;
            updateProgress(Math.floor((processedCount / missingUris.length) * 100));
        }
    } else {
        updateProgress(100);
    }
    
    return results;
  }

  async function fetchPopularityForMultipleTracks(
    tracks,
    updateProgress,
    totalProgressSteps = 1,
    skipNetworkForIds = new Set()
  ) {
    const trackIds = tracks.map((track) => {
        if (Spicetify.URI.isLocal(track.uri)) return null;
        return track.trackId || (track.uri ? track.uri.split(':')[2] : null);
    }).filter(Boolean);
    const uniqueTrackIds = [...new Set(trackIds)];
    
    const cachedMetadata = await idb.getMany('trackMetadata', uniqueTrackIds, CACHE_EXPIRE_METADATA);
    
    const missingIds = uniqueTrackIds.filter(id => {
        if (skipNetworkForIds.has(id)) return false;
        const meta = cachedMetadata.get(id);
        return !meta || meta.popularity === undefined || meta.popularity === null;
    });

    let batchSize = 500;
    let tracksProcessed = 0;
    let failedCount = 0;
    let networkIssuesInBatch = 0;

    const processInternalItem = async (id) => {
        let data = null;
        let maxRetries = 3;
        let delay = 1000;

        for (let attempt = 0; attempt <= maxRetries; attempt++) {
            data = await fetchInternalTrackMetadata(id);
            if (data) break;

            if (attempt === 0) networkIssuesInBatch++;

            if (attempt < maxRetries) {
                const jitter = Math.floor(Math.random() * 500);
                await new Promise(r => setTimeout(r, delay + jitter));
                delay *= 2;
            }
        }

        if (data) {
            const cacheData = formatTrackCacheData(data);
            const existing = cachedMetadata.get(id);
            if (existing) {
                if (existing.external_ids) {
                    cacheData.external_ids = { ...existing.external_ids, ...cacheData.external_ids };
                }
                if (existing.album) {
                    cacheData.album = { ...existing.album, ...cacheData.album };
                    if (existing.album.album_type) {
                        cacheData.album.album_type = existing.album.album_type;
                    }
                }
                if (existing.albumType) {
                    cacheData.albumType = existing.albumType;
                }
            }
            cachedMetadata.set(data.id, cacheData);
            return { key: data.id, val: cacheData };
        } else {
            failedCount++;
            return null;
        }
    };

    for (let i = 0; i < missingIds.length; ) {
      const batch = missingIds.slice(i, i + batchSize);
      networkIssuesInBatch = 0;
      
      const batchResults = await Promise.all(batch.map(id => processInternalItem(id)));
      const entriesToSave = batchResults.filter(Boolean);
      
      if (idb.setMany && entriesToSave.length > 0) {
          await idb.setMany('trackMetadata', entriesToSave);
      }
      
      if (i === 0 && batchSize === 500 && networkIssuesInBatch > 5) {
          console.warn(`[Sort-Play] Network stress detected (${networkIssuesInBatch} drops). Downshifting batch size to 250 for remaining tracks.`);
          batchSize = 250;
      }
      
      tracksProcessed += batch.length;
      const intermediateProgress = Math.round(
          ((tracksProcessed / missingIds.length) * 100) / totalProgressSteps
      );
      if (updateProgress) updateProgress(intermediateProgress);
      
      i += batch.length;
      
      if (i < missingIds.length) {
          await new Promise(r => setTimeout(r, 50));
      }
    }

    if (failedCount > 0) {
        console.warn(`[Sort-Play] failed to fetch popularity for ${failedCount} tracks (Network error/Dropped connection).`);
    }

    return tracks.map(track => {
        const id = track.trackId || (track.uri ? track.uri.split(':')[2] : null);
        const meta = cachedMetadata.get(id);
        
        let releaseDate = track.releaseDate;
        let albumName = track.albumName;
        let explicit = track.explicit || track.track?.explicit || false;

        if (meta) {
            if (meta.album && meta.album.release_date) releaseDate = meta.album.release_date;
            if (meta.album && meta.album.name) albumName = meta.album.name;
            if (meta.explicit !== undefined) explicit = meta.explicit;
        }
        
        let finalPop = track.popularity;
        if (meta && meta.popularity !== undefined && meta.popularity !== null) {
            finalPop = meta.popularity;
        } else if (finalPop === undefined) {
            finalPop = null;
        }

        return {
            ...track,
            popularity: finalPop,
            releaseDate: releaseDate,
            albumName: albumName,
            explicit: explicit
        };
    });
  }

  async function getTrackDetailsWithReleaseDate(track) {
    if (Spicetify.URI.isLocal(track.uri)) {
        return { ...track, releaseDate: null, trackNumber: track.trackNumber || 0 };
    }
    const trackId = track.uri.split(":")[2];

    const cached = await idb.get('releaseDates', trackId, CACHE_EXPIRE_RELEASE_DATE);
    
    if (cached && typeof cached === 'object' && cached.trackNumber !== undefined) {
        return { ...track, releaseDate: cached.date, trackNumber: cached.trackNumber };
    }

    try {
        const fetchedMetaMap = await fetchCoreMetadataBatch([track.uri]);
        const meta = fetchedMetaMap.get(track.uri);
        if (meta && meta.releaseDate) {
            await setCachedReleaseDate(trackId, meta.releaseDate, track.trackNumber || 0);
            return { ...track, releaseDate: meta.releaseDate, trackNumber: track.trackNumber || 0 };
        }
    } catch (e) {
        console.warn("[Sort-Play] Fast single release date fetch failed, falling back", e);
    }

    let albumId;
    if (track.albumId) {
      albumId = track.albumId;
    } else if (track.albumUri) {
      albumId = track.albumUri.split(":")[2];
    } else {
      console.warn(`Could not determine album ID for track ${track.name}`);
      return { ...track, releaseDate: cached?.date || cached || null, trackNumber: cached?.trackNumber || 0 };
    }

    try {
      if (albumTracksDataCache[albumId]) {
        const trackData = albumTracksDataCache[albumId].find(t => t.uri === track.uri);
        if (trackData && trackData.releaseDate) {
          setCachedReleaseDate(trackId, trackData.releaseDate, trackData.trackNumber).catch(() => {});
          return { ...track, releaseDate: trackData.releaseDate, trackNumber: trackData.trackNumber };
        }
      }

      const releaseDate = await getReleaseDatesForAlbum(albumId);
      
      let trackNumber = 0;
      if (albumTracksDataCache[albumId]) {
          const trackData = albumTracksDataCache[albumId].find(t => t.uri === track.uri);
          if (trackData) {
              trackNumber = trackData.trackNumber;
          }
      }

      return { ...track, releaseDate: releaseDate, trackNumber: trackNumber };
    } catch (error) {
      try {
          const meta = await fetchInternalTrackMetadata(trackId);
          if (meta && meta.album && meta.album.release_date) {
              await setCachedReleaseDate(trackId, meta.album.release_date);
              return { ...track, releaseDate: meta.album.release_date, trackNumber: track.trackNumber || 0 };
          }
      } catch (e) {}
      console.error(`Error getting release date for track ${track.name} (album ${albumId}):`, error);
      return { ...track, releaseDate: cached?.date || cached || null, trackNumber: cached?.trackNumber || 0 };
    }
  }
  
  async function _fetchLastFmTrackInfoCore(artistName, trackName, username = null, useFallback = false) {
    const maxRetries = 5;
    let delay = 1000;

    for (let retries = 0; retries < maxRetries; retries++) {
      try {
        const params = new URLSearchParams({
          method: 'track.getInfo',
          artist: artistName,
          track: trackName,
          format: 'json'
        });
        if (username) params.set('username', username);
        if (lastFmAutocorrect) params.set('autocorrect', '1');

        let response = await fetchLfmWithGateway(params);
        let text = await response.text();
        if (!text || text.trim() === '') throw new Error("Received empty response from Last.fm");
        
        let data = JSON.parse(text);

        if (data && data.error === 17) {
            return data;
        }

        if (!response.ok && (!data || data.error !== 6)) {
            throw new Error(`Last.fm API request failed with status ${response.status}`);
        }

        if (data.error === 6 && useFallback) {
          params.set('autocorrect', lastFmAutocorrect ? '0' : '1');
          const responseRetry = await fetchLfmWithGateway(params);
          const textRetry = await responseRetry.text();
          if (textRetry && textRetry.trim() !== '') {
            const dataRetry = JSON.parse(textRetry);
            if (!dataRetry.error) data = dataRetry;
          }
        }
        return data;
      } catch (error) {
        if (retries === maxRetries - 1) throw error;
        await new Promise(resolve => setTimeout(resolve, delay));
        delay *= 2;
      }
    }
  }

  function getLfmInfo(track) {
      if (!track) return null;
      let trackId = null;
      if (track.uri) {
          trackId = Spicetify.URI.isLocal(track.uri) ? track.uri : track.uri.split(":")[2];
      } else if (track.track && track.track.id) {
          trackId = track.track.id;
      } else if (track.id) {
          trackId = track.id;
      }

      const overrides = getLfmOverrides();
      const override = trackId ? overrides[trackId] : null;

      let artistName = override ? override.artist : (getPrimaryArtistName(track) || track.metadata?.artist_name);
      let trackName = override ? override.track : (track.name || track.songTitle || track.metadata?.title);

      if (trackName) trackName = trackName.trim();

      if (!artistName || !trackName) return null;
      return {
          artistName,
          trackName,
          key: `${artistName.toLowerCase()}|-|${trackName.toLowerCase()}`
      };
  }

  async function getTrackDetailsWithScrobbles(track, useFallback = false, skipCacheWrite = false, skipCacheRead = false) {
    const lfmInfo = getLfmInfo(track);
    if (!lfmInfo) {
      return { ...track, scrobbles: null, error: "Missing track title or artist name", errorLabel: "No Meta" };
    }

    const isLocal = Spicetify.URI.isLocal(track.uri);
    if (!isLocal && !skipCacheRead) {
        const cachedScrobbles = await idb.get('scrobbles', lfmInfo.key, CACHE_EXPIRE_GLOBAL_SCROBBLES);
        if (cachedScrobbles !== null && cachedScrobbles !== undefined) {
            return { ...track, scrobbles: cachedScrobbles };
        }
    }

    try {
      const username = loadLastFmUsername();
      let data = await _fetchLastFmTrackInfoCore(lfmInfo.artistName, lfmInfo.trackName, username, useFallback);

      if (data && data.error === 17 && username) {
          data = await _fetchLastFmTrackInfoCore(lfmInfo.artistName, lfmInfo.trackName, null, useFallback);
      }

      if (data.error) {
        if (data.error === 6) { 
          if (!isLocal && !skipCacheWrite) {
              await setCachedScrobbles(lfmInfo.key, -1);
              if (username) await setCachedPersonalScrobbles(lfmInfo.key, -1, false);
          }
          return { ...track, scrobbles: -1, personalScrobbles: -1, error: "Track not found on Last.fm", errorLabel: "N/A" };
        }
        throw new Error(`Last.fm API error: ${data.message}`);
      }

      let scrobbles = 0;
      const rawCount = data.track?.playcount;
      if (rawCount !== undefined && rawCount !== null && rawCount !== '') {
           const parsed = parseInt(rawCount, 10);
           if (!isNaN(parsed)) scrobbles = parsed;
      }

      const resTrack = { ...track, scrobbles };
      if (username && data.track?.userplaycount !== undefined) {
          const userCount = parseInt(data.track.userplaycount, 10);
          if (!isNaN(userCount)) resTrack.personalScrobbles = userCount;
      }

      if (!isLocal && !skipCacheWrite) {
          await setCachedScrobbles(lfmInfo.key, scrobbles);
          if (resTrack.personalScrobbles !== undefined) {
              await setCachedPersonalScrobbles(lfmInfo.key, resTrack.personalScrobbles, false);
          }
      }

      return resTrack;
    } catch (error) {
      console.error(`Error fetching scrobbles for track ${track.name}:`, error);
      return { ...track, scrobbles: null, error: "Failed to fetch from Last.fm after multiple attempts.", errorLabel: "Failed" };
    }
  }

  async function getTrackDetailsWithPersonalScrobbles(track, useFallback = false, skipCacheWrite = false, skipCacheRead = false) {
    const isLocal = Spicetify.URI.isLocal(track.uri);
    if (isLocal && (!track.name || !track.artistName)) {
        return { ...track, personalScrobbles: null, error: "Local file missing metadata.", errorLabel: "No Meta" };
    }

    const lfmInfo = getLfmInfo(track);
    if (!lfmInfo) {
        return { ...track, personalScrobbles: null, error: "Invalid track data.", errorLabel: "Invalid" };
    }

    const isCurrentTrack = track.uri === currentTrackUriForScrobbleCache;
    let cachedData = null;
    
    if (!isLocal && !skipCacheRead) {
        cachedData = await getCachedPersonalScrobbles(lfmInfo.key);
    }

    const LFM_UPDATE_LAG_COOLDOWN = 3 * 60 * 1000; 
    
    if (cachedData && !isCurrentTrack) {
        if (!cachedData.pendingUpdate) return { ...track, personalScrobbles: cachedData.count };
        if ((Date.now() - cachedData.ts) < LFM_UPDATE_LAG_COOLDOWN) return { ...track, personalScrobbles: cachedData.count };
    }

    const username = loadLastFmUsername();
    if (!username) {
      return { ...track, personalScrobbles: null, error: "Last.fm username not set.", errorLabel: "No User" };
    }

    try {
      const data = await _fetchLastFmTrackInfoCore(lfmInfo.artistName, lfmInfo.trackName, username, useFallback);

      if (data.error) {
        if (data.error === 17) {
            return { ...track, personalScrobbles: -1, error: "Last.fm profile is private. Make your listening history public.", errorLabel: "Private" };
        }
        if (data.error === 6) { 
          if (!isLocal && !skipCacheWrite) {
              await setCachedPersonalScrobbles(lfmInfo.key, -1, false);
              await setCachedScrobbles(lfmInfo.key, -1);
          }
          return { ...track, personalScrobbles: -1, scrobbles: -1, error: "Track not found on Last.fm", errorLabel: "N/A" };
        }
        throw new Error(`Last.fm API error: ${data.message}`);
      }
      
      let newScrobbleCount = 0;
      const rawCount = data.track?.userplaycount;
      if (rawCount !== undefined && rawCount !== null && rawCount !== '') {
           const parsed = parseInt(rawCount, 10);
           if (!isNaN(parsed)) newScrobbleCount = parsed;
      }
      
      const resTrack = { ...track, personalScrobbles: newScrobbleCount };
      if (data.track?.playcount !== undefined) {
          const globalCount = parseInt(data.track.playcount, 10);
          if (!isNaN(globalCount)) resTrack.scrobbles = globalCount;
      }

      if (!isLocal && !isCurrentTrack && !skipCacheWrite) {
          const oldScrobbleCount = cachedData ? cachedData.count : -1;
          if (newScrobbleCount > oldScrobbleCount) {
              await setCachedPersonalScrobbles(lfmInfo.key, newScrobbleCount, false);
          } else if (cachedData && cachedData.pendingUpdate) {
              await setCachedPersonalScrobbles(lfmInfo.key, newScrobbleCount, true);
          } else {
              await setCachedPersonalScrobbles(lfmInfo.key, newScrobbleCount, false);
          }

          if (resTrack.scrobbles !== undefined) {
              await setCachedScrobbles(lfmInfo.key, resTrack.scrobbles);
          }
      }

      return resTrack;

    } catch (error) {
      console.error(`Error fetching personal scrobbles for track ${lfmInfo.trackName}:`, error);
      return { ...track, personalScrobbles: null, error: "Failed to fetch after multiple attempts.", errorLabel: "Failed" };
    }
  }

  async function getTrackDetailsWithLastScrobbled(track, useFallback = false) {
    const isLocal = Spicetify.URI.isLocal(track.uri);
    if (isLocal && (!track.name || !track.artistName)) {
        return { ...track, lastScrobbled: null, error: "Local file missing metadata.", errorLabel: "No Meta" };
    }
    
    const lfmInfo = getLfmInfo(track);
    if (!lfmInfo) {
        return { ...track, lastScrobbled: null, error: "Invalid track data.", errorLabel: "Invalid" };
    }

    const cachedData = await idb.get('lastScrobbledDates', lfmInfo.key, CACHE_EXPIRE_PERSONAL_SCROBBLES);
    
    if (cachedData !== null && cachedData !== undefined && !isLocal) {
        return { ...track, lastScrobbled: cachedData };
    }

    const username = loadLastFmUsername();
    if (!username) {
      return { ...track, lastScrobbled: null, error: "Last.fm username not set.", errorLabel: "No User" };
    }

    try {
      const maxRetries = 5;
      let delay = 1000;
      let data = null;
      
      for (let retries = 0; retries < maxRetries; retries++) {
          try {
              const params = new URLSearchParams({
                  method: 'user.getTrackScrobbles',
                  user: username,
                  artist: lfmInfo.artistName,
                  track: lfmInfo.trackName,
                  limit: '1',
                  format: 'json'
              });
              if (lastFmAutocorrect) params.set('autocorrect', '1');

              let response = await fetchLfmWithGateway(params);
              let text = await response.text();
              if (!text || text.trim() === '') throw new Error("Received empty response from Last.fm");
              
              data = JSON.parse(text);

              if (data && data.error === 17) {
                  break;
              }

              if (!response.ok && (!data || data.error !== 6)) {
                  throw new Error(`Last.fm API request failed with status ${response.status}`);
              }

              if (data.error === 6 && useFallback) {
                  params.set('autocorrect', lastFmAutocorrect ? '0' : '1');
                  const responseRetry = await fetchLfmWithGateway(params);
                  const textRetry = await responseRetry.text();
                  if (textRetry && textRetry.trim() !== '') {
                      const dataRetry = JSON.parse(textRetry);
                      if (!dataRetry.error) data = dataRetry;
                  }
              }
              break;
          } catch (error) {
              if (retries === maxRetries - 1) throw error;
              await new Promise(resolve => setTimeout(resolve, delay));
              delay *= 2;
          }
      }

      if (data && data.error) {
        if (data.error === 17) {
            return { ...track, lastScrobbled: -1, error: "Last.fm profile is private. Make your listening history public.", errorLabel: "Private" };
        }
        if (data.error === 6) { 
          if (!isLocal) await idb.set('lastScrobbledDates', lfmInfo.key, -1);
          return { ...track, lastScrobbled: -1, error: "Track not found on Last.fm", errorLabel: "N/A" };
        }
        throw new Error(`Last.fm API error: ${data.message}`);
      }
      
      let lastScrobbled = 0;
      let isNowPlaying = false;
      let tracksArr = data?.trackscrobbles?.track;
      if (tracksArr) {
          if (!Array.isArray(tracksArr)) tracksArr = [tracksArr];
          if (tracksArr.length > 0) {
              const mostRecent = tracksArr[0];
              if (mostRecent.date && mostRecent.date.uts) {
                  lastScrobbled = parseInt(mostRecent.date.uts, 10) * 1000;
              } else if (mostRecent['@attr'] && mostRecent['@attr'].nowplaying === 'true') {
                  lastScrobbled = Date.now();
                  isNowPlaying = true;
              }
          }
      }
      
      if (!isLocal && !isNowPlaying) {
          await idb.set('lastScrobbledDates', lfmInfo.key, lastScrobbled);
      }

      return { ...track, lastScrobbled: lastScrobbled };

    } catch (error) {
      console.error(`Error fetching last scrobbled for track ${lfmInfo.trackName}:`, error);
      return { ...track, lastScrobbled: null, error: "Failed to fetch after multiple attempts.", errorLabel: "Failed" };
    }
  }
  
  function createInnerButton(sortType, parentButton, svg) {
    const innerButton = document.createElement("button");
    const isGroupingSort = sortType === 'filterAlbums' || sortType === 'filterAlbumsEPs' || sortType === 'filterAlbumsCompilations' || sortType === 'filterAlbumsEPsCompilations' || sortType === 'filterAlbumsEPsSingles';
    
    innerButton.removeAttribute("title");
    innerButton.appendChild(svg);

    innerButton.style.cssText = `
      background-color: transparent;
      border: none;
      border-radius: 2px;
      padding: 0;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      width: ${isGroupingSort ? "35px" : "32px"};
      height: ${isGroupingSort ? "35px" : "32px"};
      margin-left: 10px;
      margin-right: -10px;
      flex-shrink: 0;
    `;

    const updateTooltipPosition = (tooltip) => {
        if (!innerButton || !tooltip) return;
        const rect = innerButton.getBoundingClientRect();
        const tooltipRect = tooltip.getBoundingClientRect();
        const viewportWidth = window.innerWidth;
        const margin = 10;

        let left = rect.left + (rect.width / 2) - (tooltipRect.width / 2);
        
        if (left + tooltipRect.width > viewportWidth - margin) {
            left = viewportWidth - tooltipRect.width - margin;
        }
        if (left < margin) {
            left = margin;
        }

        tooltip.style.left = `${left}px`;
        tooltip.style.top = `${rect.top - tooltipRect.height - 8}px`;
    };

    innerButton.addEventListener("mouseenter", (e) => {
      if (isGroupingSort) {
          svg.style.stroke = "#1ED760";
      } else {
          svg.style.fill = "#1ED760";
      }
      
      const tooltipText = isGroupingSort 
        ? (sortOrderState[sortType] ? "Ungroup Albums" : "Group by Album")
        : "Toggle Order (Ascending/Descending)";

      const tooltip = document.createElement("div");
      tooltip.className = "sort-play-custom-tooltip";
      tooltip.innerText = tooltipText;
      tooltip.style.cssText = `
        position: fixed;
        background-color: #282828;
        color: #fff;
        padding: 5px 10px;
        border-radius: 4px;
        font-size: 12px;
        box-shadow: 0 4px 8px rgba(0,0,0,0.4);
        z-index: 10000;
        pointer-events: none;
        white-space: nowrap;
        opacity: 0;
        transition: opacity 0.2s;
      `;
      
      document.body.appendChild(tooltip);
      updateTooltipPosition(tooltip);
      
      requestAnimationFrame(() => { 
          tooltip.style.opacity = "1"; 
      });
      
      innerButton._tooltip = tooltip;
    });

    innerButton.addEventListener("mouseleave", () => {
      if (isGroupingSort) {
          svg.style.stroke = '#ffffffe6';
      } else {
          svg.style.fill = 'currentColor';
      }
      
      if (innerButton._tooltip) {
          innerButton._tooltip.remove();
          innerButton._tooltip = null;
      }
    });

    innerButton.addEventListener("click", (event) => {
      event.stopPropagation();
      sortOrderState[sortType] = !sortOrderState[sortType];
      localStorage.setItem(`sort-play-${sortType}-reverse`, sortOrderState[sortType]);
      
      const path = svg.querySelector("path");
      if (path) {
          const isReverse = sortOrderState[sortType];
          if (isGroupingSort) {
              path.setAttribute("d", isReverse ? ICON_PATHS.groupAlbum : ICON_PATHS.ungroupList);
              
              if (innerButton._tooltip) {
                  innerButton._tooltip.innerText = isReverse ? "Ungroup Albums" : "Group by Album";
                  updateTooltipPosition(innerButton._tooltip);
              }
          } else {
              path.setAttribute("d", isReverse ? ICON_PATHS.sortAsc : ICON_PATHS.sortDesc);
          }
      }
    });

    return innerButton;
  }

  function createInnerPlayButton() {
    const innerButton = document.createElement("button");
    innerButton.title = "Shuffle and Add to Queue";
    innerButton.innerHTML = innerPlayPlusIconSvg;

    const buttonBgColor = "rgba(var(--spice-rgb-selected-row), 0.03)";
    const buttonHoverBgColor = "rgba(var(--spice-rgb-selected-row), 0.2)";

    innerButton.style.cssText = `
      color: #ffffffe6;
      border: 1px solid rgba(255, 255, 255, 0.1);
      border-radius: 8px;
      padding: 0;
      width: 35px;
      height: 25px;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background-color 0.1s ease;
      margin-left: auto;
      margin-right: -3px;
      flex-shrink: 0;
    `;

    innerButton.style.backgroundColor = buttonBgColor;

    innerButton.addEventListener("mouseenter", () => {
      innerButton.style.backgroundColor = buttonHoverBgColor;
    });

    innerButton.addEventListener("mouseleave", () => {
      innerButton.style.backgroundColor = buttonBgColor;
    });

    innerButton.addEventListener("click", async (event) => {
      event.stopPropagation();
      innerButton.style.backgroundColor = buttonBgColor;
      
      startProcessing();

      try {
        await executeShuffleAndPlay(getCurrentUri());
      } catch (error) {
        console.error("Error during shuffle and play:", error);
        showNotification(error.message, true);
      } finally {
        resetButtons();
      }
    });

    return innerButton;
  }

